// 五行查询函数
function getWuxingInfo(ele) {
  return WUXING_ALL[ele] || null;
}
function getWuxingByColor(color) {
  var map = {'绿色':'木','青色':'木','红色':'火','紫色':'火','黄色':'土','棕色':'土','白色':'金','银色':'金','黑色':'水','蓝色':'水'};
  for (var k in map) { if (color.indexOf(k) >= 0) return map[k]; }
  return null;
}
function getWuxingByNumber(n) {
  var last = n % 10;
  if (last === 1 || last === 6) return '水';
  if (last === 2 || last === 7) return '火';
  if (last === 3 || last === 8) return '木';
  if (last === 4 || last === 9) return '金';
  if (last === 5 || last === 0) return '土';
  return null;
}
function getWuxingFood(ele) {
  var info = WUXING_ALL[ele];
  return info ? info.食物 : '';
}
function getWuxingOrgan(ele) {
  var info = WUXING_ALL[ele];
  return info ? info.器官 : '';
}
function getWuxingCareer(ele) {
  var info = WUXING_ALL[ele];
  return info ? info.职业 : '';
}

try { window.WUXING_ALL = WUXING_ALL; } catch(e){}
try { window.getWuxingInfo = getWuxingInfo; } catch(e){}
