try { window.getWuxingByNumber = getWuxingByNumber; } catch(e){}
try { window.getWuxingFood = getWuxingFood; } catch(e){}
try { window.getWuxingOrgan = getWuxingOrgan; } catch(e){}
try { window.getWuxingCareer = getWuxingCareer; } catch(e){}


