          {num:'2',name:'供灯',desc:'点燃后诵',chant:'愿此灯光，照十方界',note:'酥油灯为佳'},
          {num:'3',name:'供水',desc:'清晨换新水，七杯排列',chant:'',note:'白水为供'}
