// 神煞计算
function getShensha(pillars, dayStemIdx, dayBranchIdx) {
  // ═══ 升级：完整神煞判定（检查四柱，修复驿马/桃花/华盖的bug） ═══
  const yBranch = pillars[0].branch;
  const mBranch = pillars[1].branch;
  const dBranch = pillars[2].branch;
  const hBranch = pillars[3].branch;
  const allBranches = [yBranch, mBranch, dBranch, hBranch];
  const dayStem = STEMS[dayStemIdx];
  const result = [];

  // 天乙贵人（以日干查，检查年日时支）
  // 歌诀：甲戊庚牛羊（丑未）, 乙己鼠猴乡（子申）, 丙丁猪鸡位（亥酉）, 辛遇虎马乡（寅午）, 壬癸兔蛇藏（卯巳）
  const tianyiMap = {0:[1,7],1:[0,8],2:[9,11],3:[9,11],4:[1,7],5:[0,8],6:[9,11],7:[6,2],8:[5,3],9:[5,3]};
  const tianyiBranches = (tianyiMap[dayStemIdx] || []).map(function(b){return BRANCHES[b];});
  var hasTianyi = false;
  for (var i = 0; i < allBranches.length; i++) {
    if (tianyiBranches.indexOf(allBranches[i]) >= 0) { hasTianyi = true; break; }
  }
  if (hasTianyi) result.push({name:'天乙贵人', desc:'吉星高照，逢凶化吉，遇难成祥，贵人多助。'});

  // 驿马（以年支查，检查月日时支）
  var maMap = {'寅':'申','午':'申','戌':'申','申':'寅','子':'寅','辰':'寅','巳':'亥','酉':'亥','丑':'亥','亥':'巳','卯':'巳','未':'巳'};
  var maTarget = maMap[yBranch];
  if (maTarget && [mBranch, dBranch, hBranch].indexOf(maTarget) >= 0) {
    result.push({name:'驿马', desc:'奔波走动之象，适合外出、调动、旅行。多主在外发展。'});
  }

  // 桃花（以年支/日支查）
  var taoMap = {'寅':'卯','午':'卯','戌':'卯','申':'酉','子':'酉','辰':'酉','巳':'午','酉':'午','丑':'午','亥':'子','卯':'子','未':'子'};
  var taoTargets = [taoMap[yBranch], taoMap[dBranch]];
  var hasTao = false;
  for (var i = 0; i < allBranches.length; i++) {
    if (taoTargets.indexOf(allBranches[i]) >= 0) { hasTao = true; break; }
  }
  if (hasTao) result.push({name:'桃花', desc:'感情丰富，人缘佳，姻缘运强，利于社交。'});

  // 华盖（以年支/日支查）
  var hgMap = {'寅':'戌','午':'戌','戌':'戌','申':'辰','子':'辰','辰':'辰','巳':'丑','酉':'丑','丑':'丑','亥':'未','卯':'未','未':'未'};
  var hgTargets = [hgMap[yBranch], hgMap[dBranch]];
  var hasHg = false;
  for (var i = 0; i < allBranches.length; i++) {
    if (hgTargets.indexOf(allBranches[i]) >= 0) { hasHg = true; break; }
  }
  if (hasHg) result.push({name:'华盖', desc:'艺术之星，利于艺术创作、学术研究，性情孤高。'});

  // 文昌贵人（以日干查）
  var wenchangMap = {0:'巳',1:'午',2:'申',3:'酉',4:'申',5:'酉',6:'亥',7:'子',8:'寅',9:'卯'};
  var wcTarget = wenchangMap[dayStemIdx];
  if (wcTarget && allBranches.indexOf(wcTarget) >= 0) {
    result.push({name:'文昌贵人', desc:'学业之星，利考试、学习、著述、文职升迁。'});
  }

  // 羊刃（以日干查，只看月支为真刃）
  var yangrenMap = {0:'卯',1:'辰',2:'午',3:'未',4:'午',5:'未',6:'酉',7:'戌',8:'子',9:'丑'};
  var yrTarget = yangrenMap[dayStemIdx];
  if (yrTarget) {
    if (mBranch === yrTarget) result.push({name:'月刃（真羊刃）', desc:'刚暴之星在月令，利于武职、竞争，慎防血光官非。'});
    else if (allBranches.indexOf(yrTarget) >= 0) result.push({name:'羊刃', desc:'刚暴之星，性格刚毅，慎防血光、官非。'});
  }

  // 将星（以年支查）
  var jiangMap = {'寅':'午','午':'午','戌':'午','申':'子','子':'子','辰':'子','巳':'酉','酉':'酉','丑':'酉','亥':'卯','卯':'卯','未':'卯'};
  var jiangTarget = jiangMap[yBranch];
  if (jiangTarget && allBranches.indexOf(jiangTarget) >= 0) {
    result.push({name:'将星', desc:'掌权之星，利于军警、领导岗位，有威信。'});
  }

  // 亡神（以年支查）
  var wsMap = {'寅':'巳','午':'巳','戌':'巳','申':'亥','子':'亥','辰':'亥','巳':'申','酉':'申','丑':'申','亥':'寅','卯':'寅','未':'寅'};
  var wsTarget = wsMap[yBranch];
  if (wsTarget && allBranches.indexOf(wsTarget) >= 0) {
    result.push({name:'亡神', desc:'主谋略、暗算，善谋则成，失谋则败。'});
  }

  // 劫煞（以年支查）
  var jsMap = {'寅':'亥','午':'亥','戌':'亥','申':'巳','子':'巳','辰':'巳','巳':'寅','酉':'寅','丑':'寅','亥':'申','卯':'申','未':'申'};
  var jsTarget = jsMap[yBranch];
  if (jsTarget && allBranches.indexOf(jsTarget) >= 0) {
    result.push({name:'劫煞', desc:'主意外损失，慎防破财、被盗。'});
  }

  // 孤辰寡宿（以年支查）
  var guchenMap = {'寅':['巳','丑'],'卯':['巳','丑'],'辰':['巳','丑'],'巳':['申','辰'],'午':['申','辰'],'未':['申','辰'],'申':['亥','未'],'酉':['亥','未'],'戌':['亥','未'],'亥':['寅','戌'],'子':['寅','戌'],'丑':['寅','戌']};
  var gc = guchenMap[yBranch];
  if (gc) {
    if (allBranches.indexOf(gc[0]) >= 0) result.push({name:'孤辰', desc:'性情孤独，人际薄弱，宜配合同居或团队生活。'});
    if (allBranches.indexOf(gc[1]) >= 0) result.push({name:'寡宿', desc:'婚恋波折，晚婚倾向，宜化解。'});
  }

  // 学堂（以日干查）
  var xtMap = {0:'亥',1:'午',2:'寅',3:'酉',4:'寅',5:'酉',6:'巳',7:'子',8:'申',9:'卯'};
  var xtTarget = xtMap[dayStemIdx];
  if (xtTarget && allBranches.indexOf(xtTarget) >= 0) {
    result.push({name:'学堂', desc:'学业之星，聪明好学，利读书升学。'});
  }

  // 金舆（以日干查）= 禄神地支+2位
  var jyMap = {0:'辰',1:'巳',2:'未',3:'申',4:'未',5:'申',6:'戌',7:'亥',8:'丑',9:'寅'};
  var jyTarget = jyMap[dayStemIdx];
  if (jyTarget && allBranches.indexOf(jyTarget) >= 0) {
    result.push({name:'金舆', desc:'富贵之星，有车马之福，利财运。'});
  }

  // 国印贵人（以日干查，检查四柱地支）
  var gyinMap = {0:'戌',1:'亥',2:'丑',3:'寅',4:'丑',5:'寅',6:'辰',7:'巳',8:'未',9:'申'};
  var gyinTarget = gyinMap[dayStemIdx];
  if (gyinTarget && allBranches.indexOf(gyinTarget) >= 0) {
    result.push({name:'国印贵人', desc:'掌印之星，主权力、地位，利于仕途、公职。'});
  }

  // 词馆（R3.8修正：日干帝旺处，详见后文R3.8补充）
  // 旧版词馆映射有误，已在R3.8中修正为帝旺处

  // 禄神（以日干查）
  var lushenMap = {0:'寅',1:'卯',2:'巳',3:'午',4:'巳',5:'午',6:'申',7:'酉',8:'亥',9:'子'};
  var lsTarget = lushenMap[dayStemIdx];
  if (lsTarget && allBranches.indexOf(lsTarget) >= 0) {
    result.push({name:'禄神', desc:'食禄之星，主衣食无忧、福气浓厚。逢禄则喜，代表稳定的收入来源。'});
  }

  // 红艳煞（以日干查）
  var hongyanMap = {0:'午',1:'午',2:'寅',3:'未',4:'辰',5:'辰',6:'戌',7:'酉',8:'子',9:'申'};
  var hyTarget = hongyanMap[dayStemIdx];
  if (hyTarget && allBranches.indexOf(hyTarget) >= 0) {
    result.push({name:'红艳煞', desc:'感情之星，主异性缘佳、感情丰富。过旺则易招桃花是非。'});
  }

  // 天德贵人（以月支查）
  var tiandeMap = {'寅':'丁','卯':'申','辰':'壬','巳':'辛','午':'亥','未':'甲','申':'癸','酉':'寅','戌':'丙','亥':'乙','子':'巳','丑':'庚'};
  var tdTarget = tiandeMap[mBranch];
  if (tdTarget) {
    // 检查天干或地支（天德贵人可以是天干或地支）
    var allStems = pillars.map(function(p){return p.stem;});
    if (allStems.indexOf(tdTarget) >= 0 || allBranches.indexOf(tdTarget) >= 0) {
      result.push({name:'天德贵人', desc:'万利皆解，化凶为吉。主一生平安，灾厄化解。'});
    }
  }

  // 月德贵人（以月支查天干）
  var yuedeMap = {'寅':'丙','卯':'甲','辰':'壬','巳':'庚','午':'丙','未':'甲','申':'壬','酉':'庚','戌':'丙','亥':'甲','子':'壬','丑':'庚'};
  var ydTarget = yuedeMap[mBranch];
  if (ydTarget) {
    var allStems2 = pillars.map(function(p){return p.stem;});
    if (allStems2.indexOf(ydTarget) >= 0) {
      result.push({name:'月德贵人', desc:'慈祥仁善，化解灾厄。主一生少病，逢凶化吉。'});
    }
  }

  // 三奇贵人（以日干查，检查四柱天干是否含三奇组合）
  // 《珞琭子三命消息赋》云："甲戊庚为天上三奇，乙丙丁为地下三奇，壬癸辛为人中三奇"
  // 天上三奇：甲、戊、庚全见；地下三奇：乙、丙、丁全见；人中三奇：壬、癸、辛全见
  var allStemsForQi = pillars.map(function(p){return p.stem;});
  var hasSanqi = false;
  var sanqiType = '';
  // 天上三奇：甲戊庚
  if (allStemsForQi.indexOf('甲') >= 0 && allStemsForQi.indexOf('戊') >= 0 && allStemsForQi.indexOf('庚') >= 0) {
    hasSanqi = true; sanqiType = '天上三奇';
  }
  // 地下三奇：乙丙丁
  if (!hasSanqi && allStemsForQi.indexOf('乙') >= 0 && allStemsForQi.indexOf('丙') >= 0 && allStemsForQi.indexOf('丁') >= 0) {
    hasSanqi = true; sanqiType = '地下三奇';
  }
  // 人中三奇：壬癸辛
  if (!hasSanqi && allStemsForQi.indexOf('壬') >= 0 && allStemsForQi.indexOf('癸') >= 0 && allStemsForQi.indexOf('辛') >= 0) {
    hasSanqi = true; sanqiType = '人中三奇';
  }
  if (hasSanqi) {
    result.push({name:'三奇贵人（' + sanqiType + '）', desc:'三奇贵人入命，精神卓绝，博学多能，为奇人异士之命。主才华横溢，逢凶化吉，福泽深厚。'});
  }

  // 魁罡（日柱为庚辰/庚戌/壬辰/戊戌）
  var kgDays = ['庚辰','庚戌','壬辰','戊戌'];
  var dayPillar = dayStem + dBranch;
  if (kgDays.indexOf(dayPillar) >= 0) {
    result.push({name:'魁罡', desc:'性格刚烈果断，聪敏果断，有领导才能。慎防婚姻不顺。'});
  }

  // ═══ R3.8: 神煞补全 ═══

  // 天赦日（春戊寅、夏甲午、秋戊申、冬甲子）
  var tiansheDays = {
    '春': ['戊寅'],
    '夏': ['甲午'],
    '秋': ['戊申'],
    '冬': ['甲子']
  };
  // 判断季节
  var seasonMap = {'寅':'春','卯':'春','辰':'春','巳':'夏','午':'夏','未':'夏','申':'秋','酉':'秋','戌':'秋','亥':'冬','子':'冬','丑':'冬'};
  var curSeason = seasonMap[mBranch] || '冬';
  var tiansheTargets = tiansheDays[curSeason] || [];
  if (tiansheTargets.indexOf(dayPillar) >= 0) {
    result.push({name:'天赦日', desc:'天赦日为天地赦罪之日，百无禁忌，逢凶化吉。宜祈福、消灾、和解、忏悔，万事皆吉。'});
  }

  // 词馆（修正：日干帝旺处）
  // 甲见卯、乙见子、丙戊见午、丁己见酉、庚见酉、辛见申、壬见子、癸见亥
  var ciguanMapV2 = {0:'卯',1:'子',2:'午',3:'酉',4:'午',5:'酉',6:'酉',7:'申',8:'子',9:'亥'};
  var cgTargetV2 = ciguanMapV2[dayStemIdx];
  if (cgTargetV2 && allBranches.indexOf(cgTargetV2) >= 0) {
    result.push({name:'词馆(帝旺)', desc:'词馆为日干帝旺处，主口才极佳、善于辞令，利于演讲、写作、外交、学术。'});
  }

  // ═══ R3.8: 神煞与柱位关联分析 ═══
  // 年柱神煞看祖辈、月柱看父母、日柱看自身、时柱看子女
  // 为已有神煞补充柱位信息
  var pillarNames = ['年柱', '月柱', '日柱', '时柱'];
  var pillarScope = ['祖辈根基', '父母兄弟', '自身配偶', '子女晚辈'];
  for (var si = 0; si < result.length; si++) {
    var shenshaItem = result[si];
    // 检查该神煞出现在哪些柱位
    var locations = [];
    // 天乙贵人
    if (shenshaItem.name === '天乙贵人') {
      var tianyiIdx = tianyiMap[dayStemIdx] || [];
      for (var pi = 0; pi < allBranches.length; pi++) {
        if (tianyiIdx.indexOf(BRANCHES.indexOf(allBranches[pi])) >= 0) locations.push(pillarNames[pi]);
      }
    }
    // 驿马
    if (shenshaItem.name === '驿马') {
      var maT = maMap[yBranch];
      for (var pi2 = 1; pi2 < allBranches.length; pi2++) {
        if (allBranches[pi2] === maT) locations.push(pillarNames[pi2]);
      }
    }
    // 桃花
    if (shenshaItem.name === '桃花') {
      for (var pi3 = 0; pi3 < allBranches.length; pi3++) {
        if (allBranches[pi3] === taoMap[yBranch] || allBranches[pi3] === taoMap[dBranch]) locations.push(pillarNames[pi3]);
      }
    }
    // 华盖
    if (shenshaItem.name === '华盖') {
      for (var pi4 = 0; pi4 < allBranches.length; pi4++) {
        if (allBranches[pi4] === hgMap[yBranch] || allBranches[pi4] === hgMap[dBranch]) locations.push(pillarNames[pi4]);
      }
    }
    // 文昌
    if (shenshaItem.name === '文昌贵人') {
      for (var pi5 = 0; pi5 < allBranches.length; pi5++) {
        if (allBranches[pi5] === wenchangMap[dayStemIdx]) locations.push(pillarNames[pi5]);
      }
    }
    // 羊刃
    if (shenshaItem.name.indexOf('羊刃') >= 0) {
      for (var pi6 = 0; pi6 < allBranches.length; pi6++) {
        if (allBranches[pi6] === yangrenMap[dayStemIdx]) locations.push(pillarNames[pi6]);
      }
    }
    // 学堂
    if (shenshaItem.name === '学堂') {
      for (var pi7 = 0; pi7 < allBranches.length; pi7++) {
        if (allBranches[pi7] === xtMap[dayStemIdx]) locations.push(pillarNames[pi7]);
      }
    }
    // 词馆(帝旺)
    if (shenshaItem.name.indexOf('词馆') >= 0) {
      for (var pi8 = 0; pi8 < allBranches.length; pi8++) {
        if (allBranches[pi8] === cgTargetV2) locations.push(pillarNames[pi8]);
      }
    }
    // 禄神
    if (shenshaItem.name === '禄神') {
      for (var pi9 = 0; pi9 < allBranches.length; pi9++) {
        if (allBranches[pi9] === lushenMap[dayStemIdx]) locations.push(pillarNames[pi9]);
      }
    }
    // 天德贵人
    if (shenshaItem.name === '天德贵人') {
      var tdT = tiandeMap[mBranch];
      var allStemsArr = pillars.map(function(p){return p.stem;});
      for (var pi10 = 0; pi10 < allStemsArr.length; pi10++) {
        if (allStemsArr[pi10] === tdT) locations.push(pillarNames[pi10]);
      }
      for (var pi10b = 0; pi10b < allBranches.length; pi10b++) {
        if (allBranches[pi10b] === tdT && locations.indexOf(pillarNames[pi10b]) < 0) locations.push(pillarNames[pi10b]);
      }
    }
    // 月德贵人
    if (shenshaItem.name === '月德贵人') {
      var ydT = yuedeMap[mBranch];
      var allStemsArr2 = pillars.map(function(p){return p.stem;});
      for (var pi11 = 0; pi11 < allStemsArr2.length; pi11++) {
        if (allStemsArr2[pi11] === ydT) locations.push(pillarNames[pi11]);
      }
    }
    // 亡神
    if (shenshaItem.name === '亡神') {
      for (var pi12 = 0; pi12 < allBranches.length; pi12++) {
        if (allBranches[pi12] === wsTarget) locations.push(pillarNames[pi12]);
      }
    }
    // 劫煞
    if (shenshaItem.name === '劫煞') {
      for (var pi13 = 0; pi13 < allBranches.length; pi13++) {
        if (allBranches[pi13] === jsTarget) locations.push(pillarNames[pi13]);
      }
    }
    // 将星
    if (shenshaItem.name === '将星') {
      for (var pi14 = 0; pi14 < allBranches.length; pi14++) {
        if (allBranches[pi14] === jiangTarget) locations.push(pillarNames[pi14]);
      }
    }
    // 天赦日 — 日柱专属
    if (shenshaItem.name === '天赦日') {
      locations.push('日柱');
    }
    // 魁罡 — 日柱专属
    if (shenshaItem.name === '魁罡') {
      locations.push('日柱');
    }

    // 补充柱位释义
    if (locations.length > 0) {
      var scopeTexts = [];
      for (var li = 0; li < locations.length; li++) {
        var pIdx = pillarNames.indexOf(locations[li]);
        if (pIdx >= 0) scopeTexts.push(locations[li] + '(' + pillarScope[pIdx] + ')');
      }
      shenshaItem.pillarLocations = locations.join('、');
      shenshaItem.pillarScope = scopeTexts.join('、');
    }
  }

  // 返回全部神煞（不再限制15个）
  return result;
}

