// --- 日干支五行强弱（基于地支藏干加权） ---
function _getDayWuxingStrength(dayGZ) {
  var gan = TIAN_GAN[dayGZ.gan];
  var zhi = DI_ZHI[dayGZ.zhi];
  var eleScore = {木:0,火:0,土:0,金:0,水:0};
  // 天干五行
  eleScore[ELE[gan]] += 3;
  // 地支藏干五行
  var canggan = ZHI_CANGGAN[zhi] || [];
  var weights = [2, 1, 0.5];
  for (var i = 0; i < canggan.length; i++) {
    if (canggan[i]) {
      eleScore[ELE[canggan[i]]] += (weights[i] || 0);
    }
  }
  // 找最强五行
  var strongest = '金', maxScore = 0;
  for (var k in eleScore) {
    if (eleScore[k] > maxScore) { maxScore = eleScore[k]; strongest = k; }
  }
  return {strongest: strongest, scores: eleScore, ganWuxing: ELE[gan]};
}

// --- 日支与缘主日支关系 ---
function _checkZhiRelation(bzDayZhiIdx, dayZhiIdx) {
  var relations = [];
  // 六合
  for (var i = 0; i < LIU_HE.length; i++) {
    if ((LIU_HE[i][0] === bzDayZhiIdx && LIU_HE[i][1] === dayZhiIdx) ||
        (LIU_HE[i][1] === bzDayZhiIdx && LIU_HE[i][0] === dayZhiIdx)) {
      relations.push({type: '六合', score: 8, desc: '日支相合，和谐顺遂'});
    }
  }
  // 三合
  for (var i = 0; i < SAN_HE.length; i++) {
    if (SAN_HE[i].indexOf(bzDayZhiIdx) !== -1 && SAN_HE[i].indexOf(dayZhiIdx) !== -1) {
      relations.push({type: '三合', score: 6, desc: '日支三合，贵人相助'});
    }
  }
  // 六冲
  var chongPairs = [[0,6],[1,7],[2,8],[3,9],[4,10],[5,11]];
  for (var i = 0; i < chongPairs.length; i++) {
    if ((chongPairs[i][0] === bzDayZhiIdx && chongPairs[i][1] === dayZhiIdx) ||
        (chongPairs[i][1] === bzDayZhiIdx && chongPairs[i][0] === dayZhiIdx)) {
      relations.push({type: '六冲', score: -10, desc: '日支相冲，气场相克，大忌'});
    }
  }
  // 六害
  for (var i = 0; i < ZHI_HAI_PAIRS.length; i++) {
    if ((ZHI_HAI_PAIRS[i].a === DI_ZHI[bzDayZhiIdx] && ZHI_HAI_PAIRS[i].b === DI_ZHI[dayZhiIdx]) ||
        (ZHI_HAI_PAIRS[i].b === DI_ZHI[bzDayZhiIdx] && ZHI_HAI_PAIRS[i].a === DI_ZHI[dayZhiIdx])) {
      relations.push({type: '六害', score: -6, desc: '日支相害，暗中不利'});
    }
  }
  // 三刑
  var xingSan = ['寅巳申','丑未戌'];
  for (var i = 0; i < xingSan.length; i++) {
    var set = xingSan[i].split('');
    var inBz = false, inDay = false;
    for (var j = 0; j < set.length; j++) {
      if (DI_ZHI[bzDayZhiIdx] === set[j]) inBz = true;
      if (DI_ZHI[dayZhiIdx] === set[j]) inDay = true;
    }
    if (inBz && inDay) {
      relations.push({type: '三刑', score: -8, desc: '日支犯刑，是非纠葛'});
    }
  }
  return relations;
}

// --- 当前节气判定 ---
function _getCurrentJieqi(date) {
  var m = date.getMonth() + 1;
  var d = date.getDate();
  for (var i = JIEQI_APPROX_DATE.length - 1; i >= 0; i--) {
    var jq = JIEQI_APPROX_DATE[i];
    if (m > jq.month || (m === jq.month && d >= jq.day)) {
      return {name: jq.name, daysFrom: 0};
    }
  }
  // 如果在一月小寒之前
  return {name: JIEQI_APPROX_DATE[JIEQI_APPROX_DATE.length - 1].name, daysFrom: 0};
}

// --- 计算距离最近节气的天数 ---
function _daysFromJieqi(date, jieqiName) {
  var m = date.getMonth() + 1;
  var d = date.getDate();
  for (var i = 0; i < JIEQI_APPROX_DATE.length; i++) {
    if (JIEQI_APPROX_DATE[i].name === jieqiName) {
      var jqM = JIEQI_APPROX_DATE[i].month;
      var jqD = JIEQI_APPROX_DATE[i].day;
      var jqDate = new Date(date.getFullYear(), jqM - 1, jqD);
      return Math.floor((date - jqDate) / 86400000);
    }
  }
  return 0;
}

// --- 方位推算（从城市名） ---
function _getCityDirection(cityName) {
  if (!cityName) return null;
  // 精确匹配
  for (var c in CITY_DIRECTION_WUXING) {
    if (cityName.indexOf(c) === 0) return CITY_DIRECTION_WUXING[c];
  }
  // 关键词匹配
  for (var d in DIRECTION_KEYWORDS) {
    var keywords = DIRECTION_KEYWORDS[d];
    for (var k = 0; k < keywords.length; k++) {
      if (cityName.indexOf(keywords[k]) >= 0) {
        return {direction: d, wuxing: d === '北' ? '水' : d === '南' ? '火' : d === '东' ? '木' : d === '西' ? '金' : '土', shaConflict: d === '北' ? '南' : d === '南' ? '北' : d === '东' ? '西' : d === '西' ? '东' : ''};
      }
    }
  }
  return null;
}

// --- 五行生克关系字符串 ---
function _wuxingRelationFam(ele1, ele2) {
  // ele1 对 ele2 的关系
  if (ele1 === ele2) return '相同';
  var sheng = {木:'火',火:'土',土:'金',金:'水',水:'木'};
  var ke = {木:'土',土:'水',水:'火',火:'金',金:'木'};
  if (sheng[ele1] === ele2) return '生';
  if (sheng[ele2] === ele1) return '被生';
  if (ke[ele1] === ele2) return '克';
  if (ke[ele2] === ele1) return '被克';
  return '无直接关系';
}

// --- 从八字数据提取用神详情 ---
function _extractYongShen(baziData) {
  var mingType = baziData.mingType || {};
  var dayStem = baziData.dayStem;
  var dayEle = baziData.dayWuxing;
  var isStrong = baziData.isStrong;
  
  // 喜用神
  var xiEle = baziData.xiEle;
  var yongshen = mingType.yongshen || '';
  var yongshenEle = mingType.yongshenEle || xiEle;
  
  // 忌神五行（克用神者或生忌神者）
  var keXiEle = null;
  var wuxingKe = {木:'金',火:'水',土:'木',金:'火',水:'土'};
  var wuxingShengXi = null;
  var wuxingSheng = {木:'水',火:'木',土:'火',金:'土',水:'金'};
  keXiEle = wuxingKe[yongshenEle] || wuxingKe[xiEle] || '';
  wuxingShengXi = wuxingSheng[yongshenEle] || wuxingSheng[xiEle] || '';
  
  return {
    dayStem: dayStem,
    dayEle: dayEle,
    isStrong: isStrong,
    xiEle: xiEle,
    yongshen: yongshen,
    yongshenEle: yongshenEle,
    jiEle: keXiEle || '火',
    shengXiEle: wuxingShengXi || '水',
    strengthLevel: mingType.strengthLevel || (isStrong ? '偏强' : '偏弱'),
    stemIdx: baziData.dayStemIdx,
    branchIdx: baziData.dayBranchIdx
  };
}

// --- 字节气偏好评分 ---
function _scoreJieqi(date, eventConfig) {
  var curJq = _getCurrentJieqi(date);
  var daysFrom = _daysFromJieqi(date, curJq.name);
  var score = 3; // 基础分
  var detail = '';
  
  if (eventConfig.jieqi && eventConfig.jieqi.length > 0) {
    var found = false;
    for (var i = 0; i < eventConfig.jieqi.length; i++) {
      if (curJq.name === eventConfig.jieqi[i]) {
        score = 5;
        detail = '正值' + curJq.name + '前后，' + (eventConfig.jieqiBonus || '节气当令');
        found = true;
        break;
      }
    }
    if (!found) {
      // 在吉节气之后30天内
      for (var i = 0; i < eventConfig.jieqi.length; i++) {
        var jqDays = _daysFromJieqi(date, eventConfig.jieqi[i]);
        if (jqDays >= 0 && jqDays <= 30) {
          score = 4;
          detail = eventConfig.jieqi[i] + '后' + jqDays + '天，' + (eventConfig.jieqiBonus || '节气余气');
          found = true;
          break;
        }
      }
    }
    if (!found) {
      detail = curJq.name + '后' + daysFrom + '天';
    }
  } else {
    detail = curJq.name + '后' + daysFrom + '天';
  }
  
  // 节气交替日减分
  if (daysFrom <= 1) {
    score = Math.max(0, score - 1);
    detail += '（节气交替日，气场不稳）';
  }
  
  return {score: score, detail: detail, curJq: curJq};
}

// --- 职业匹配评分 ---
function _scoreCareer(dayGZ, career, baziYongShen) {
  if (!career) return {score: 10, detail: '未选职业'};
  
  var careerEle = CAREER_WUXING[career];
  if (!careerEle || careerEle === '综合') {
    return {score: 12, detail: '自由职业，五行综合考量'};
  }
  
  var dayWuxing = _getDayWuxingStrength(dayGZ);
  var score = 10; // 基础分
  var detailParts = [];
  
  // 日干五行与职业五行的关系
  var rel = _wuxingRelation(dayWuxing.ganWuxing, careerEle);
  detailParts.push(career + '属' + careerEle);
  
  if (rel === '生') {
    score += 3;
    detailParts.push('日生职业五行（付出有回报）');
  } else if (rel === '被生') {
    score += 4;
    detailParts.push('职业五行生日（职业助运）');
  } else if (rel === '相同') {
    score += 2;
    detailParts.push('五行相同（中规中矩）');
  } else if (rel === '克') {
    score -= 2;
    detailParts.push('日克职业五行（劳心费力）');
  } else if (rel === '被克') {
    score -= 1;
    detailParts.push('职业五行克日（压力较大）');
  }
  
  // 职业专属吉神匹配在第4层处理，这里只做五行基础分
  score = Math.min(15, Math.max(5, score));
  
  return {score: score, detail: detailParts.join('，'), careerEle: careerEle};
}

// ================================================================
// precisionZeRi - 核心精准择日函数
// ================================================================
function precisionZeRi(userInfo, purpose) {
  var result = {
    userInfo: userInfo,
    purpose: purpose,
    candidates: [],
    avoidDates: [],
    report: null
  };
  
  // === 获取八字数据 ===
  var bDate = userInfo.birthDate ? new Date(userInfo.birthDate + 'T12:00:00') : new Date(1990, 0, 1);
  var birthYear = bDate.getFullYear();
  var birthMonth = bDate.getMonth() + 1;
  var birthDay = bDate.getDate();
  var birthHour = parseInt(userInfo.birthHour) || 0;
  var birthSex = userInfo.sex || 'male';
  
  var baziData = {};
  try {
    baziData = getBaziCalcData(birthYear, birthMonth, birthDay, birthHour, birthSex);
  } catch(e) {
    baziData = {dayStem: '甲', dayBranch: '子', dayStemIdx: 0, dayBranchIdx: 0, dayWuxing: '木', xiEle: '水', isStrong: false, mingType: {strengthLevel: '偏弱', yongshenEle: '水', yongshen: ''}};
  }
  
  var ys = _extractYongShen(baziData);
  
  // === 事项配置 ===
  var eventConfig = PRECISION_EVENT_CONFIG[purpose] || {
    jianchu: ['开','成','满'], good: ['天恩','月恩'], bad: ['月破'],
    jieqi: [], jieqiBonus: '', desc: purpose
  };
  
  // === 搜索范围：支持向前向后选日 ===
  var searchStart, searchEnd;
  if (userInfo.startDate) {
    searchStart = new Date(userInfo.startDate + 'T12:00:00');
  } else {
    searchStart = new Date();
  }
  searchStart.setHours(12, 0, 0, 0);
  if (userInfo.endDate) {
    searchEnd = new Date(userInfo.endDate + 'T12:00:00');
  } else {
    searchEnd = new Date(searchStart);
    searchEnd.setDate(searchEnd.getDate() + 60);
  }
  searchEnd.setHours(12, 0, 0, 0);
  var totalDays = Math.round((searchEnd - searchStart) / 86400000);
  if (totalDays < 1) totalDays = 60;
  if (totalDays > 365) totalDays = 365;

  for (var i = 0; i < totalDays; i++) {
    var d = new Date(searchStart);
    d.setDate(d.getDate() + i);
    d.setHours(12, 0, 0, 0);
    
    var Y = d.getFullYear(), M = d.getMonth() + 1, D = d.getDate();
    var yearGZ = getYearGanZhi(Y, M, D);
    var monthGZ = getMonthGanZhi(Y, M, D);
    var dayGZ = getDayGanZhi(Y, M, D);
    
    // === 基础数据 ===
    var jcName = getJianChu(monthGZ.zhi, dayGZ.zhi);
    var jsList = calcJishen(yearGZ, monthGZ, dayGZ);
    var xsList = calcXiongshen(yearGZ, monthGZ, dayGZ);
    var zs = getZhishen(dayGZ.gan, dayGZ.zhi);
    var zsHuangdao = ZHISHEN_TYPE[zs];
    
    // ===== 7层评分 =====
    var scores = {};
    var details = {};
    
    // -- 第1层：日干支与日主关系（30分） --
    var dayWxStrength = _getDayWuxingStrength(dayGZ);
    var dayGanEle = dayWxStrength.ganWuxing;
    var s1Score = 20; // 基础分
    var s1Detail = [];
    
    // 日干是否生/克日主
    var rel = _wuxingRelation(ys.dayEle, dayGanEle);
    if (rel === '被生') {
      s1Score += 8;
      s1Detail.push('日干' + dayGanEle + '生日主' + ys.dayEle + '（吉）');
    } else if (rel === '生') {
      s1Score -= 3;
      s1Detail.push('日主生日干（泄气）');
    } else if (rel === '被克') {
      s1Score -= 5;
      s1Detail.push('日干克日主（忌）');
    } else if (rel === '相同') {
      if (ys.isStrong) {
        s1Score -= 2;
        s1Detail.push('日干与日主相同，身强不喜比劫');
      } else {
        s1Score += 3;
        s1Detail.push('日干与日主相同，比劫帮身');
      }
    }
    
    // 日干是否喜用神
    if (dayGanEle === ys.yongshenEle || dayGanEle === ys.xiEle) {
      s1Score += 5;
      s1Detail.push('日干为喜用神' + dayGanEle);
    } else if (dayGanEle === ys.jiEle) {
      s1Score -= 4;
      s1Detail.push('日干为忌神' + dayGanEle);
    }
    
    // 日支关系
    var zhiRelations = _checkZhiRelation(ys.branchIdx, dayGZ.zhi);
    var zhiScore = 0;
    for (var z = 0; z < zhiRelations.length; z++) {
      zhiScore += zhiRelations[z].score;
      s1Detail.push('日支' + zhiRelations[z].type + '：' + zhiRelations[z].desc);
    }
    s1Score += Math.max(-6, Math.min(6, zhiScore));
    
    s1Score = Math.max(5, Math.min(30, s1Score));
    scores.l1 = s1Score;
    details.l1 = '日主' + ys.dayEle + (ys.isStrong ? '偏强' : '偏弱') + '，喜' + ys.xiEle + '，忌' + ys.jiEle + '。' + TIAN_GAN[dayGZ.gan] + DI_ZHI[dayGZ.zhi] + '日，' + s1Detail.join('；');
    
    // -- 第2层：建除十二神与事项匹配（20分） --
    var s2Score = 10;
    var s2Detail = '';
    if (eventConfig.jianchu && eventConfig.jianchu.indexOf(jcName) !== -1) {
      s2Score = 20;
      s2Detail = '建除「' + jcName + '」日，宜' + purpose;
    } else {
      var yiList = JIAN_CHU_YI[jcName] || ['祭祀'];
      var matchYi = false;
      for (var yi = 0; yi < yiList.length; yi++) {
        if (yiList[yi].indexOf(purpose) >= 0 || purpose.indexOf(yiList[yi]) >= 0) {
          matchYi = true; break;
        }
      }
      if (matchYi) {
        s2Score = 15;
        s2Detail = '建除「' + jcName + '」日，宜表中含' + purpose + '项';
      } else {
        s2Score = 8;
        s2Detail = '建除「' + jcName + '」日，非' + purpose + '首选';
      }
    }
    scores.l2 = s2Score;
    details.l2 = s2Detail;
    
    // -- 第3层：吉神凶神综合评分（20分） --
    var s3Score = 10;
    var s3Good = [];
    var s3Bad = [];
    
    if (eventConfig.good) {
      for (var g = 0; g < eventConfig.good.length; g++) {
        if (jsList.indexOf(eventConfig.good[g]) !== -1) {
          s3Good.push(eventConfig.good[g]);
        }
      }
    }
    if (eventConfig.bad) {
      for (var b = 0; b < eventConfig.bad.length; b++) {
        if (xsList.indexOf(eventConfig.bad[b]) !== -1) {
          s3Bad.push(eventConfig.bad[b]);
        }
      }
    }
    // 事项专属吉神加分
    if (eventConfig.specialtyGods && eventConfig.specialtyGods.good) {
      var specCount = 0;
      for (var sg = 0; sg < eventConfig.specialtyGods.good.length; sg++) {
        if (jsList.indexOf(eventConfig.specialtyGods.good[sg]) !== -1) specCount++;
      }
      s3Score += Math.min(eventConfig.specialtyGods.bonus || 3, specCount * 2);
    }
    
    s3Score += s3Good.length * 3;
    s3Score -= s3Bad.length * 5;
    if (zsHuangdao) s3Score += 2;
    
    s3Score = Math.max(3, Math.min(20, s3Score));
    scores.l3 = s3Score;
    details.l3 = (s3Good.length > 0 ? '吉神' + s3Good.join('、') + '齐聚' : '无匹配吉神') +
      (s3Bad.length > 0 ? '；凶神' + s3Bad.join('、') + '不利' : '；无重凶神') +
      '。' + (zsHuangdao ? '黄道' : '黑道') + '日，值神' + zs;
    
    // -- 第4层：职业匹配度（15分） --
    var careerResult = _scoreCareer(dayGZ, userInfo.career, ys);
    scores.l4 = careerResult.score;
    details.l4 = careerResult.detail;
    
    // -- 第5层：方位考量（10分） --
    var cityInfo = _getCityDirection(userInfo.city);
    var s5Score = 7;
    var s5Detail = '';
    var shaInfo = CHONGSHA_DETAIL[DI_ZHI[dayGZ.zhi]] || {chong:'?', sha:'?'};
    
    if (cityInfo) {
      s5Detail = '所在地' + (userInfo.city || '未知') + '位于' + cityInfo.direction + '方（五行' + cityInfo.wuxing + '），';
      if (shaInfo.sha === cityInfo.shaConflict) {
        s5Score -= 3;
        s5Detail += '当日煞' + shaInfo.sha + '，与所在地方位相冲，不宜出行';
      } else {
        s5Score += 2;
        s5Detail += '当日煞' + shaInfo.sha + '，不影响' + cityInfo.direction + '方出行';
      }
    } else {
      s5Detail = '所在地未知，方位评分默认';
      // 即使不知道城市，也显示煞方信息
      s5Detail += '；当日煞' + shaInfo.sha + (shaInfo.sha === '北' ? '（不宜北行）' : shaInfo.sha === '东' ? '（不宜东行）' : shaInfo.sha === '西' ? '（不宜西行）' : '（不宜南行）');
    }
    scores.l5 = Math.max(3, Math.min(10, s5Score));
    details.l5 = s5Detail;
    
    // -- 第6层：节气与流月（5分） --
    var jieqiResult = _scoreJieqi(d, eventConfig);
    scores.l6 = jieqiResult.score;
    details.l6 = jieqiResult.detail;
    
    // -- 第7层：三元九运维度（5分） --
    var syScore = 0;
    var syDetail = '';
    var _curYY = getCurrentYuanYun(d.getFullYear());
    var _yunWx = _curYY.wuxing;
    var _dayGanEle = ELE[TIAN_GAN[dayGZ.gan]] || '木';
    var _dayZhiEle = {子:'水',丑:'土',寅:'木',卯:'木',辰:'土',巳:'火',午:'火',未:'土',申:'金',酉:'金',戌:'土',亥:'水'}[DI_ZHI[dayGZ.zhi]] || '土';
    // 日干支五行属火/土：运星同气或相生，+5
    if (_dayGanEle === _yunWx || _dayZhiEle === _yunWx) { syScore = 5; syDetail = '日干支与运星同气'; }
    else if (_dayGanEle === '火' || _dayGanEle === '土' || _dayZhiEle === '火' || _dayZhiEle === '土') { syScore = 5; syDetail = '日干支五行与运星相生'; }
    // 日干支五行属水：水克运星火，-3
    else if (_dayGanEle === '水' || _dayZhiEle === '水') { syScore = -3; syDetail = '日干支五行克运星'; }
    else { syScore = 0; syDetail = '日干支五行与运星关系间接'; }
    scores.l7 = syScore;
    details.l7 = syDetail;
    
    // === 总分 ===
    var totalScore = scores.l1 + scores.l2 + scores.l3 + scores.l4 + scores.l5 + scores.l6 + scores.l7;
    
    // === 等级判定 ===
    var level = '';
    if (totalScore >= 90) level = '大吉';
    else if (totalScore >= 75) level = '吉';
    else if (totalScore >= 60) level = '平';
    else if (totalScore >= 45) level = '小凶';
    else level = '凶';
    
    var candidate = {
      date: new Date(d),
      ganzhi: TIAN_GAN[dayGZ.gan] + DI_ZHI[dayGZ.zhi],
      totalScore: totalScore,
      level: level,
      scores: scores,
      details: details,
      jianchu: jcName,
      zhishen: zs,
      isHuangdao: zsHuangdao,
      jishenList: jsList,
      xiongshenList: xsList,
      chongsha: shaInfo,
      yearGZ: yearGZ,
      monthGZ: monthGZ,
      dayGZ: dayGZ,
      jieqiInfo: jieqiResult
    };
    
    result.candidates.push(candidate);
  }
  
  // 排序
  result.candidates.sort(function(a, b) {
    return b.totalScore - a.totalScore;
  });
  
  // 推荐日期前3
  result.topCandidates = result.candidates.slice(0, 3);
  // 避免日期
  result.avoidDates = result.candidates.filter(function(c) {
    return c.totalScore < 45;
  }).slice(0, 3);
  
  // 生成推演报告
  result.report = _generatePrecisionReport(result, ys, baziData, userInfo);
  
  return result;
}

// --- 生成推演报告 ---
function _generatePrecisionReport(zeriResult, ys, baziData, userInfo) {
  var top = zeriResult.topCandidates;
  var avoid = zeriResult.avoidDates;
  var purpose = zeriResult.purpose;
  
  var weekDays = ['周日','周一','周二','周三','周四','周五','周六'];
  
  var html = '<div class="precision-report">';
  html += '<div class="pr-header">🎯 精准择日报告</div>';
  
  // 缘主信息
  var bzStr = baziData.pillars ? 
    baziData.pillars[0].stem + baziData.pillars[0].branch + '年 ' +
    baziData.pillars[1].stem + baziData.pillars[1].branch + '月 ' +
    baziData.pillars[2].stem + baziData.pillars[2].branch + '日 ' +
    baziData.pillars[3].stem + baziData.pillars[3].branch + '时'
    : ys.dayStem + ys.dayEle + '日主';
  
  html += '<div class="pr-meta">';
  html += '<span>缘主：' + (userInfo.name || '善信') + '</span>';
  html += '<span>八字：' + bzStr + '</span>';
  html += '<span>事项：' + purpose + '</span>';
  if (userInfo.career) html += '<span>职业：' + userInfo.career + '</span>';
  if (userInfo.city) html += '<span>所在地：' + userInfo.city + '</span>';
  html += '</div>';
  
  // 最佳推荐
  if (top.length > 0) {
    var best = top[0];
    var d = best.date;
    var dateStr = d.getFullYear() + '年' + (d.getMonth()+1) + '月' + d.getDate() + '日（' + weekDays[d.getDay()] + '）';
    
    html += '<div class="pr-best">';
    html += '<div class="pr-best-label">🏆 最佳推荐</div>';
    html += '<div class="pr-best-date">' + dateStr + '</div>';
    html += '<div class="pr-best-ganzhi">' + best.ganzhi + '日</div>';
    html += '<div class="pr-best-score">综合评分：<span class="pr-score-' + best.level + '">' + best.totalScore + '分/' + best.level + '</span></div>';
    html += '</div>';
    
    // 推演模型
    html += '<div class="pr-layers">';
    html += '<div class="pr-layer">├─ <b>第1层 八字用神：</b>' + best.details.l1 + ' （+' + best.scores.l1 + '/30）</div>';
    html += '<div class="pr-layer">├─ <b>第2层 建除事项：</b>' + best.details.l2 + ' （+' + best.scores.l2 + '/20）</div>';
    html += '<div class="pr-layer">├─ <b>第3层 吉凶神：</b>' + best.details.l3 + ' （+' + best.scores.l3 + '/20）</div>';
    html += '<div class="pr-layer">├─ <b>第4层 职业匹配：</b>' + best.details.l4 + ' （+' + best.scores.l4 + '/15）</div>';
    html += '<div class="pr-layer">├─ <b>第5层 方位：</b>' + best.details.l5 + ' （+' + best.scores.l5 + '/10）</div>';
    html += '<div class="pr-layer">├─ <b>第6层 节气：</b>' + best.details.l6 + ' （+' + best.scores.l6 + '/5）</div>';
    
    // 总评
    var zongping = _generateZongping(best, ys, userInfo, purpose);
    html += '<div class="pr-layer pr-zongping">└─ <b>总评：</b>' + zongping + '</div>';
    html += '</div>';
  }
  
  // 备选日期
  if (top.length > 1) {
    html += '<div class="pr-alt-section">';
    html += '<div class="pr-alt-title">📅 备选日期</div>';
    for (var i = 1; i < top.length; i++) {
      var alt = top[i];
      var altD = alt.date;
      html += '<div class="pr-alt-item">';
      html += '<span class="pr-alt-rank">' + (i+1) + '. </span>';
      html += '<span class="pr-alt-date">' + (altD.getMonth()+1) + '月' + altD.getDate() + '日</span>';
      html += '<span class="pr-alt-score">' + alt.totalScore + '分/' + alt.level + '</span>';
      html += '<span class="pr-alt-gz">' + alt.ganzhi + '日</span>';
      html += '</div>';
    }
    html += '</div>';
  }
  
  // 避免日期
  if (avoid.length > 0) {
    html += '<div class="pr-avoid-section">';
    html += '<div class="pr-avoid-title">⚠️ 避免日期</div>';
    for (var i = 0; i < avoid.length; i++) {
      var av = avoid[i];
      var avD = av.date;
      html += '<div class="pr-avoid-item">';
      html += '<span>' + (avD.getMonth()+1) + '月' + avD.getDate() + '日</span>';
      html += '<span class="pr-avoid-score">' + av.totalScore + '分/' + av.level + '</span>';
      html += '<span>' + av.ganzhi + '日</span>';
      html += '<span style="opacity:.6">' + (av.xiongshenList.length > 0 ? av.xiongshenList.slice(0,2).join('、') + '忌' : '') + '</span>';
      html += '</div>';
    }
    html += '</div>';
  }
  
  // AI建议区域
  html += '<div class="pr-ai-section" id="precZeriAiAdvice">';
  html += '<div class="pr-ai-title">💡 综合建议</div>';
  html += '<div class="pr-ai-content" id="precZeriAiText">正在生成个性化建议...</div>';
  html += '</div>';
  
  html += '</div>';
  
  // 异步生成AI建议
  setTimeout(function() {
    _generateAiAdvice(userInfo, purpose, zeriResult, ys);
  }, 100);
  
  return html;
}

// --- 生成总评 ---
function _generateZongping(best, ys, userInfo, purpose) {
  var parts = [];
  var dayWxStrength = _getDayWuxingStrength(best.dayGZ);
  
  // 八字维度
  var rel = _wuxingRelation(ys.dayEle, dayWxStrength.ganWuxing);
  if (rel === '被生') {
    parts.push(dayWxStrength.ganWuxing + '生' + ys.dayEle + '，用神得力');
  } else if (rel === '相同') {
    parts.push('比劫帮身，' + (ys.isStrong ? '需注意过旺' : '力量增强'));
  } else if (rel === '被克') {
    parts.push('日干克日主，用神受制');
  }
  
  // 建除
  parts.push('建除' + best.jianchu + '日宜' + purpose);
  
  // 吉神
  if (best.jishenList && best.jishenList.length > 0) {
    parts.push(best.jishenList.slice(0, 3).join('+') + '助');
  }
  
  // 职业
  if (userInfo.career && CAREER_WUXING[userInfo.career]) {
    parts.push(userInfo.career + '者得' + CAREER_WUXING[userInfo.career] + '气相助');
  }
  
  return parts.join('，') + '。择此日' + purpose + '大吉。';
}

// --- AI建议生成 ---
function _generateAiAdvice(userInfo, purpose, zeriResult, ys) {
  var el = document.getElementById('precZeriAiText');
  if (!el) return;
  
  var best = zeriResult.topCandidates.length > 0 ? zeriResult.topCandidates[0] : null;
  if (!best) {
    el.innerHTML = '暂无推荐日期，请调整查询参数。';
    return;
  }
  
  // 尝试调用AI
  if (typeof callYIDAO === 'function') {
    var prompt = '你是一位精通传统择日学的大师（参考《协纪辨方书》《择吉汇要》）。' +
      '缘主八字日主' + ys.dayStem + ys.dayEle + '（' + ys.strengthLevel + '），喜' + ys.xiEle + '忌' + ys.jiEle + '。' +
      '推荐日期为' + best.ganzhi + '日，综合评分' + best.totalScore + '分/' + best.level + '。' +
      '事项为' + purpose + '。' +
      '请给出大白话建议（100字内），包括：为什么这天好、当天宜什么时辰、方位注意事项、催旺小方法。';
    
    try {
      callYIDAO(prompt).then(function(reply) {
        if (el) el.innerHTML = reply || _getFallbackAdvice(userInfo, purpose, best, ys);
      }).catch(function() {
        if (el) el.innerHTML = _getFallbackAdvice(userInfo, purpose, best, ys);
      });
    } catch(e) {
      el.innerHTML = _getFallbackAdvice(userInfo, purpose, best, ys);
    }
  } else {
    el.innerHTML = _getFallbackAdvice(userInfo, purpose, best, ys);
  }
}

// --- 本地降级建议 ---
function _getFallbackAdvice(userInfo, purpose, best, ys) {
  var dayWxStrength = _getDayWuxingStrength(best.dayGZ);
  var advice = '';
  
  // 基于八字+事项的综合建议
  advice += '<p>基于您的八字（' + ys.dayStem + ys.dayEle + '日主' + ys.strengthLevel + '）';
  if (userInfo.career) advice += '和' + userInfo.career + '职业';
  advice += '，' + best.ganzhi + '日为' + purpose + '之吉选。';
  
  // 为什么好
  var rel = _wuxingRelation(ys.dayEle, dayWxStrength.ganWuxing);
  if (rel === '被生') {
    advice += '此日' + dayWxStrength.ganWuxing + '旺生您日主' + ys.dayEle + '，用神得力，气场和谐。';
  } else if (rel === '相同') {
    advice += '此日五行与您日主相同，能量共振。';
  }
  advice += '</p>';
  
  // 时辰建议（精确到小时）
  var goodHour = _suggestGoodHour(best, ys);
  advice += goodHour;
  
  // 方位建议
  var cityInfo = _getCityDirection(userInfo.city);
  if (cityInfo) {
    advice += '<p>🧭 <b>方位建议：</b>出发面向' + cityInfo.direction + '方，避免' + (best.chongsha ? best.chongsha.sha : '正南') + '方。</p>';
  }
  
  // 催旺方法
  advice += '<p>🍀 <b>催旺小法：</b>';
  var cwangTips = {
    '木': '当日宜穿绿色衣服，在家中东方放四棵富贵竹。',
    '火': '当日宜穿红色衣服，在南方点一盏灯或蜡烛。',
    '土': '当日宜穿黄色衣服，在家中中央位置放黄水晶。',
    '金': '当日宜穿白色衣服，在家中西方放金属物品（铜器/硬币）。',
    '水': '当日宜穿蓝色/黑色衣服，在北方放一杯水或鱼缸。'
  };
  advice += (cwangTips[dayWxStrength.ganWuxing] || cwangTips['木']) + '</p>';
  
  // 大白话总结
  advice += '<p>📝 <b>大白话：</b>这天' + dayWxStrength.ganWuxing + '气旺，对您的' + ys.dayEle + '日主有生助之力，' + (userInfo.career || '行事') + '顺遂。建除' + best.jianchu + '日本来就宜' + purpose + '，加上吉神' + (best.jishenList && best.jishenList.length > 0 ? best.jishenList.slice(0, 3).join('、') : '庇佑') + '，是个好日子。</p>';
  
  return advice;
}

// --- 推算当日吉时（精确到小时） ---
function _suggestGoodHour(best, ys) {
  var dayGan = best.dayGZ.gan;
  var dayZhi = best.dayGZ.zhi;
  var hourNames = ['子时(23-1)','丑时(1-3)','寅时(3-5)','卯时(5-7)','辰时(7-9)','巳时(9-11)','午时(11-13)','未时(13-15)','申时(15-17)','酉时(17-19)','戌时(19-21)','亥时(21-23)'];
  var hourTimeRanges = ['23:00-01:00','01:00-03:00','03:00-05:00','05:00-07:00','07:00-09:00','09:00-11:00','11:00-13:00','13:00-15:00','15:00-17:00','17:00-19:00','19:00-21:00','21:00-23:00'];
  // 时支五行
  var zhiEle = ['水','土','木','木','土','火','火','土','金','金','土','水'];
  // 时干五行（五鼠遁）
  var dayGanIdx = (typeof dayGan === 'number') ? dayGan : 0;
  var hourStemStart = [0,2,4,6,8,10][dayGanIdx % 5]; // 甲己起甲子
  
  // 黄黑道吉时
  var d = dayGanIdx % 5;
  var hourHuangdao = [
    [0,1,4,5,10],  // 甲己日
    [2,3,4,5,10],  // 乙庚日
    [0,1,6,7,10],  // 丙辛日
    [0,1,2,3,8],   // 丁壬日
    [0,1,4,5,6]    // 戊癸日
  ];
  var goodHours = hourHuangdao[d] || [4,5,6];
  
  // 日支冲时支
  var chongMap = {0:6, 1:7, 2:8, 3:9, 4:10, 5:11, 6:0, 7:1, 8:2, 9:3, 10:4, 11:5};
  var dayZhiIdx = (typeof dayZhi === 'number') ? dayZhi : 0;
  var chongHour = chongMap[dayZhiIdx];
  
  // 逐时辰评分
  var hourScores = [];
  for (var h = 0; h < 12; h++) {
    var score = 50; // 基础分
    var reasons = [];
    
    // 1. 黄黑道（+/-15分）
    if (goodHours.indexOf(h) >= 0) {
      score += 15;
      reasons.push('黄道吉时');
    } else {
      score -= 10;
      reasons.push('黑道时辰');
    }
    
    // 2. 时支五行与喜用神（+/-20分）
    var hEle = zhiEle[h];
    if (hEle === ys.yongshenEle) {
      score += 20;
      reasons.push('时支' + hEle + '为喜用神');
    } else if (hEle === ys.dayEle) {
      if (ys.isStrong) {
        score -= 5;
        reasons.push('时支同五行，身强不喜');
      } else {
        score += 8;
        reasons.push('时支同五行，帮扶日主');
      }
    } else if (_wuxingRelation(ys.dayEle, hEle) === '被克') {
      score -= 15;
      reasons.push('时支' + hEle + '克日主');
    }
    
    // 3. 日支冲时支（-20分）
    if (h === chongHour) {
      score -= 20;
      reasons.push('日时相冲');
    }
    
    // 4. 上午/下午调整
    if (h >= 4 && h <= 7) { // 辰巳午未
      score += 5;
      reasons.push('上午阳气旺');
    } else if (h >= 10) { // 戌亥
      score -= 5;
      reasons.push('夜间阴气重');
    }
    
    hourScores.push({
      hour: h,
      name: hourNames[h],
      time: hourTimeRanges[h],
      score: Math.max(0, Math.min(100, score)),
      reasons: reasons
    });
  }
  
  // 排序取前3
  hourScores.sort(function(a,b) { return b.score - a.score; });
  var top3 = hourScores.slice(0, 3);
  
  // 生成详细建议
  var result = '<div style="margin-top:12px">';
  result += '<div style="font-size:12px;color:var(--gold);margin-bottom:8px">🕐 吉时推荐（精确到小时）</div>';
  result += '<table style="width:100%;font-size:11px">';
  for (var t = 0; t < top3.length; t++) {
    var hs = top3[t];
    var color = hs.score >= 75 ? '#27ae60' : hs.score >= 55 ? '#f39c12' : '#e74c3c';
    var label = hs.score >= 75 ? '★优选' : hs.score >= 55 ? '可用' : '慎选';
    result += '<tr style="border-bottom:1px solid rgba(201,168,76,0.08)">';
    result += '<td style="padding:4px;width:90px;color:' + color + '">' + hs.name + '</td>';
    result += '<td style="padding:4px;width:80px;color:var(--paper3);font-size:10px">' + hs.time + '</td>';
    result += '<td style="padding:4px;width:40px"><span style="color:' + color + '">' + label + '</span></td>';
    result += '<td style="padding:4px;color:var(--paper2);font-size:10px">' + hs.reasons.join('、') + '</td>';
    result += '</tr>';
  }
  result += '</table>';
  
  // 避开时辰
  var worst = hourScores.filter(function(hs) { return hs.score < 40; });
  if (worst.length > 0) {
    result += '<div style="margin-top:6px;font-size:11px;color:#e74c3c">⚠️ 避开：';
    for (var w = 0; w < worst.length; w++) {
      result += worst[w].name + '(' + worst[w].reasons.join('、') + ')';
      if (w < worst.length - 1) result += '；';
    }
    result += '</div>';
  }
  result += '</div>';
  
  return result;
}

// --- 对外调用函数（按钮触发） ---
function runPrecisionZeRi() {
  var userInfo = {
    name: document.getElementById('zeriName')?.value || document.getElementById('precZeriName')?.value || '',
    birthDate: document.getElementById('zeriBirthDate')?.value || document.getElementById('precZeriBirth')?.value || '',
    birthHour: document.getElementById('zeriBirthHour')?.value ?? document.getElementById('precZeriHour')?.value ?? '0',
    sex: document.getElementById('zeriSex')?.value || document.getElementById('precZeriSex')?.value || 'male',
    career: document.getElementById('precZeriCareer')?.value || '',
    city: document.getElementById('zeriBirthCity')?.value || document.getElementById('precZeriBirthplace')?.value || '',
    residence: document.getElementById('zeriLiveCity')?.value || document.getElementById('precZeriResidence')?.value || '',
    startDate: document.getElementById('precZeriStartDate')?.value || '',
    endDate: document.getElementById('precZeriEndDate')?.value || ''
  };
  
  var purpose = document.getElementById('jiuriPurpose')?.value || document.getElementById('precZeriPurpose')?.value || '';
  
  if (!userInfo.birthDate) {
    showToast('请输入出生日期');
    return;
  }
  if (!purpose) {
    showToast('请选择择日事项');
    return;
  }
  
  // ═══ 收集参与人员八字 ═══
  var members = getZeriMembers();
  
  playSound('cast');
  
  var resultEl = document.getElementById('zrEngineResult') || document.getElementById('precZeriResult');
  if (resultEl) {
    resultEl.innerHTML = '<div class="loading-spinner"><div class="spinner"></div><p>正在推演八字择日...</p></div>';
    resultEl.style.display = 'block';
  }
  
  // 延迟渲染（给UI时间更新）
  setTimeout(function() {
    try {
      var result = precisionZeRi(userInfo, purpose);
      
      // ═══ 多人八字综合分析 ═══
      var multiPersonReport = '';
      if (members.length > 0) {
        multiPersonReport = analyzeMultiPersonZeri(members, purpose);
      }
      
      if (resultEl) {
        resultEl.innerHTML = result.report + multiPersonReport;
        resultEl.style.display = 'block';
        playSound('success');
        // 滚动到结果
        resultEl.scrollIntoView({behavior: 'smooth', block: 'start'});
        // === 化解方案注入 ===
        var _zrBirth = userInfo.birthDate ? userInfo.birthDate.split('-').map(Number) : null;
        var _zrHour = parseInt(userInfo.birthHour) || 12;
        var _zrDayStem = '甲';
        if (_zrBirth && _zrBirth.length === 3) {
          appendHuajieToResult(resultEl.id, _zrBirth[0], _zrBirth[1], _zrBirth[2], _zrHour, userInfo.sex, userInfo.name);
          // 计算日主天干用于三元九运
          try {
            var _zrBazi = computeBaziCore(_zrBirth[0], _zrBirth[1], _zrBirth[2], _zrHour);
            if (_zrBazi && _zrBazi.pillars && _zrBazi.pillars[2]) _zrDayStem = _zrBazi.pillars[2].stem;
          } catch(e) {}
        }
        // ═══ 三元九运择日维度 ═══
        try {
          var _syZr = _generateSanyuanJiuyunBlock('zeri', {
            dayStem: _zrDayStem,
            dayEle: ELE[_zrDayStem] || '木',
            currentYear: new Date().getFullYear()
          });
          resultEl.innerHTML += _syZr;
        } catch(e) { console.warn('[三元九运择日分析块失败]', e.message); }
        // === 导出/复制按钮 ===
        resultEl.innerHTML += '<div style="margin-top:16px;text-align:center"><button onclick="exportReportGeneric(\'' + resultEl.id + '\',\'择日分析报告\')" style="font-size:12px;color:var(--gold);background:none;border:1px solid rgba(201,168,76,.2);border-radius:20px;padding:6px 20px;cursor:pointer;letter-spacing:2px;margin:0 4px">📄 导出报告</button><button onclick="copyReportGeneric(\'' + resultEl.id + '\')" style="font-size:12px;color:var(--gold);background:none;border:1px solid rgba(201,168,76,.2);border-radius:20px;padding:6px 20px;cursor:pointer;letter-spacing:2px;margin:0 4px">📋 复制结果</button></div>';
      }
    } catch(e) {
      if (resultEl) {
        resultEl.innerHTML = '<div style="color:#e74c3c;padding:12px">择日推演出错：' + e.message + '</div>';
      }
    }
  }, 200);
}

// 导出到window
window.precisionZeRi = precisionZeRi;
window.runPrecisionZeRi = runPrecisionZeRi;

// ================================================================
// ===== 择日多人参与功能 (MULTI_PERSON_ZERI) =====
// ================================================================

var _zeriMembers = [];
var _zeriMemberIdCounter = 0;

/**
 * 添加择日参与人
 */
function addZeriMember() {
  if (_zeriMembers.length >= 6) {
    showToast('最多添加6位参与人');
    return;
  }
  _zeriMemberIdCounter++;
  _zeriMembers.push({
    id: 'zm' + _zeriMemberIdCounter,
    name: '',
    relation: '',
    birthDate: '',
    birthHour: '',
    sex: ''
  });
  renderZeriMembers();
}

/**
 * 删除择日参与人
 */
function removeZeriMember(id) {
  _zeriMembers = _zeriMembers.filter(function(m) { return m.id !== id; });
  renderZeriMembers();
}

/**
 * 更新参与人信息（输入框onchange时调用）
 */
function updateZeriMember(id, field, value) {
  for (var i = 0; i < _zeriMembers.length; i++) {
    if (_zeriMembers[i].id === id) {
      _zeriMembers[i][field] = value;
      break;
    }
  }
}

/**
 * 渲染参与人列表
 */
function renderZeriMembers() {
  var container = document.getElementById('zeriMembersList');
  if (!container) return;
  
  if (_zeriMembers.length === 0) {
    container.innerHTML = '<p style="font-size:12px;opacity:.3;text-align:center;padding:12px">暂无参与人，点击「+ 添加参与人」按钮添加</p>';
    return;
  }
  
  var hourOptions = '<option value="">时辰</option>' +
    '<option value="0">子时</option><option value="1">丑时</option>' +
    '<option value="2">寅时</option><option value="3">卯时</option>' +
    '<option value="4">辰时</option><option value="5">巳时</option>' +
    '<option value="6">午时</option><option value="7">未时</option>' +
    '<option value="8">申时</option><option value="9">酉时</option>' +
    '<option value="10">戌时</option><option value="11">亥时</option>';
  
  var html = '';
  _zeriMembers.forEach(function(m, idx) {
    html += '<div style="background:rgba(0,0,0,0.15);border:1px solid rgba(0,100,150,0.1);border-radius:8px;padding:12px;margin-bottom:8px" id="' + m.id + '-row">';
    html += '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px">';
    html += '<span style="font-size:12px;color:var(--cyan);letter-spacing:1px">参与人 #' + (idx + 1) + '</span>';
    html += '<button onclick="removeZeriMember(\'' + m.id + '\')" style="background:none;border:none;color:#e74c3c;cursor:pointer;font-size:14px;padding:2px 8px">✕</button>';
    html += '</div>';
    html += '<div style="display:flex;flex-wrap:wrap;gap:6px">';
    html += '<input type="text" class="input-field" placeholder="姓名" style="max-width:90px;font-size:12px" value="' + (m.name || '') + '" onchange="updateZeriMember(\'' + m.id + '\',\'name\',this.value)">';
    html += '<input type="text" class="input-field" placeholder="关系（如：配偶/父亲/合伙人）" style="max-width:140px;font-size:12px" value="' + (m.relation || '') + '" onchange="updateZeriMember(\'' + m.id + '\',\'relation\',this.value)">';
    html += '<input type="date" class="input-field" style="max-width:140px;font-size:12px" value="' + (m.birthDate || '') + '" onchange="updateZeriMember(\'' + m.id + '\',\'birthDate\',this.value)" title="出生日期">';
    html += '<select class="input-field" style="max-width:90px;font-size:12px" onchange="updateZeriMember(\'' + m.id + '\',\'birthHour\',this.value)">' + hourOptions + '</select>';
    html += '<select class="input-field" style="max-width:70px;font-size:12px" onchange="updateZeriMember(\'' + m.id + '\',\'sex\',this.value)"><option value="">性别</option><option value="male"' + (m.sex==='male'?' selected':'') + '>男</option><option value="female"' + (m.sex==='female'?' selected':'') + '>女</option></select>';
    html += '</div>';
    html += '</div>';
  });
  container.innerHTML = html;
}

/**
 * 获取参与人员八字信息数组
 */
function getZeriMembers() {
  return _zeriMembers.filter(function(m) { return m.birthDate; });
}

/**
 * 多人八字综合择日分析
 * - 避忌：日柱冲任何一人的日柱
 * - 优选：对所有人都有利的吉日
 */
function analyzeMultiPersonZeri(members, purpose) {
  if (!members || members.length === 0) return '';
  
  var HOUR_MAP = {0:23,1:1,2:3,3:5,4:7,5:9,6:11,7:13,8:15,9:17,10:19,11:21};
  
  // 计算每个参与人的八字日柱
  var memberBazis = [];
  for (var i = 0; i < members.length; i++) {
    var m = members[i];
    if (!m.birthDate) continue;
    var parts = m.birthDate.split('-');
    var y = parseInt(parts[0]), mo = parseInt(parts[1]), d = parseInt(parts[2]);
    var hour = HOUR_MAP[parseInt(m.birthHour)] || 12;
    var bazi = null;
    try { bazi = computeBaziCore(y, mo, d, hour); } catch(e) { console.warn('参与人八字计算失败:', m.name, e.message); }
    if (bazi && bazi.pillars && bazi.pillars[2]) {
      memberBazis.push({
        name: m.name || '参与人' + (i+1),
        relation: m.relation || '',
        sex: m.sex || '',
        dayPillar: bazi.pillars[2],
        dayStem: bazi.pillars[2].stem,
        dayBranch: bazi.pillars[2].branch,
        bazi: bazi
      });
    }
  }
  
  if (memberBazis.length === 0) return '';
  
  // 六冲关系
  var CHONG = { '子':'午', '午':'子', '丑':'未', '未':'丑', '寅':'申', '申':'寅', '卯':'酉', '酉':'卯', '辰':'戌', '戌':'辰', '巳':'亥', '亥':'巳' };
  
  // 五行
  var ELE_MAP = {'甲':'木','乙':'木','丙':'火','丁':'火','戊':'土','己':'土','庚':'金','辛':'金','壬':'水','癸':'水'};
  
  var html = '<div style="margin-top:24px;padding:20px;background:rgba(0,100,150,0.04);border:1px solid rgba(0,100,150,0.15);border-radius:12px">';
  html += '<h4 style="color:var(--cyan);margin-bottom:16px;letter-spacing:2px">👥 多人八字合参择日分析</h4>';
  
  // 展示参与人日柱信息
  html += '<div style="margin-bottom:16px">';
  html += '<table style="width:100%;font-size:12px;border-collapse:collapse">';
  html += '<tr style="border-bottom:1px solid rgba(201,168,76,0.1)"><th style="text-align:left;padding:6px">姓名</th><th style="text-align:left;padding:6px">关系</th><th style="text-align:left;padding:6px">日柱</th><th style="text-align:left;padding:6px">日主五行</th></tr>';
  memberBazis.forEach(function(mb) {
    var ele = ELE_MAP[mb.dayStem] || '?';
    html += '<tr style="border-bottom:1px solid rgba(255,255,255,0.03)">';
    html += '<td style="padding:6px">' + mb.name + '</td>';
    html += '<td style="padding:6px">' + (mb.relation || '—') + '</td>';
    html += '<td style="padding:6px;color:var(--gold)">' + mb.dayStem + mb.dayBranch + '</td>';
    html += '<td style="padding:6px">' + ele + '</td>';
    html += '</tr>';
  });
  html += '</table>';
  html += '</div>';
  
  // 分析日柱相冲情况
  var chongPairs = [];
  for (var i = 0; i < memberBazis.length; i++) {
    for (var j = i + 1; j < memberBazis.length; j++) {
      if (CHONG[memberBazis[i].dayBranch] === memberBazis[j].dayBranch) {
        chongPairs.push(memberBazis[i].name + '(' + memberBazis[i].dayBranch + ') ↔ ' + memberBazis[j].name + '(' + memberBazis[j].dayBranch + ')');
      }
    }
  }
  
  if (chongPairs.length > 0) {
    html += '<div style="background:rgba(231,76,60,0.06);border:1px solid rgba(231,76,60,0.15);border-radius:8px;padding:12px;margin-bottom:12px">';
    html += '<p style="color:#e74c3c;font-size:12px;margin-bottom:4px"><b>⚠️ 日柱相冲提醒</b></p>';
    chongPairs.forEach(function(p) {
      html += '<p style="font-size:11px;color:#e74c3c;opacity:.8;margin:2px 0">' + p + '</p>';
    });
    html += '<p style="font-size:11px;opacity:.6;margin-top:6px">择日时需避开冲任何一人的日柱日期，选择与所有人和合的吉日。</p>';
    html += '</div>';
  }
  
  // 综合择日建议
  html += '<div style="background:rgba(39,174,96,0.04);border:1px solid rgba(39,174,96,0.12);border-radius:8px;padding:12px">';
  html += '<p style="color:#27ae60;font-size:12px;margin-bottom:8px"><b>📅 多人择日原则</b></p>';
  html += '<ul style="font-size:11px;line-height:1.8;opacity:.8;padding-left:16px">';
  html += '<li><b>避忌：</b>所选日柱不可冲任何一位参与人的日柱（日支六冲）</li>';
  html += '<li><b>优选：</b>选择对所有参与人日主都有生扶作用的吉日</li>';
  html += '<li><b>三方相合：</b>优先选择与参与人日支形成三合、六合的日期</li>';
  html += '<li><b>五行平衡：</b>综合所有人八字五行，选择能平衡整体五行的日期</li>';
  html += '</ul>';
  
  // 列出需要避忌的日支
  var avoidBranches = [];
  memberBazis.forEach(function(mb) {
    var chongBranch = CHONG[mb.dayBranch];
    if (chongBranch && avoidBranches.indexOf(chongBranch) < 0) {
      avoidBranches.push(chongBranch);
    }
  });
  if (avoidBranches.length > 0) {
    html += '<p style="font-size:11px;color:#e74c3c;margin-top:8px"><b>需避忌日支：</b>' + avoidBranches.join('、') + '日</p>';
  }
  
  // 列出有益的日支（三合、六合）
  var SANHE = {'子':['申','辰'],'丑':['巳','酉'],'寅':['午','戌'],'卯':['亥','未'],'辰':['子','申'],'巳':['丑','酉'],'午':['寅','戌'],'未':['亥','卯'],'申':['子','辰'],'酉':['丑','巳'],'戌':['寅','午'],'亥':['卯','未']};
  var LIUHE = {'子':'丑','丑':'子','寅':'亥','亥':'寅','卯':'戌','戌':'卯','辰':'酉','酉':'辰','巳':'申','申':'巳','午':'未','未':'午'};
  var favorableBranches = [];
  memberBazis.forEach(function(mb) {
    var sanhe = SANHE[mb.dayBranch] || [];
    sanhe.forEach(function(b) { if (favorableBranches.indexOf(b) < 0) favorableBranches.push(b); });
    var lh = LIUHE[mb.dayBranch];
    if (lh && favorableBranches.indexOf(lh) < 0) favorableBranches.push(lh);
  });
  if (favorableBranches.length > 0) {
    html += '<p style="font-size:11px;color:#27ae60;margin-top:4px"><b>优选日支：</b>' + favorableBranches.join('、') + '日</p>';
  }
  
  html += '</div>';
  
  // 五行综合分析
  var eleCount = {'金':0,'木':0,'水':0,'火':0,'土':0};
  memberBazis.forEach(function(mb) {
    var ele = ELE_MAP[mb.dayStem];
    if (ele) eleCount[ele] = (eleCount[ele]||0) + 1;
  });
  html += '<div style="margin-top:12px">';
  html += '<p style="font-size:11px;opacity:.6;margin-bottom:6px">参与人日主五行分布：</p>';
  var eleColors = {'金':'#f1c40f','木':'#27ae60','水':'#3498db','火':'#e74c3c','土':'#e67e22'};
  html += '<div style="display:flex;gap:8px;flex-wrap:wrap">';
  for (var e in eleCount) {
    if (eleCount[e] > 0) {
      html += '<span style="padding:4px 10px;border-radius:12px;font-size:11px;background:' + eleColors[e] + '20;border:1px solid ' + eleColors[e] + '40;color:' + eleColors[e] + '">' + e + '×' + eleCount[e] + '</span>';
    }
  }
  html += '</div>';
  // 推荐补益五行
  var minEle = '木', minCount = 99;
  for (var e2 in eleCount) {
    if (eleCount[e2] < minCount) { minCount = eleCount[e2]; minEle = e2; }
  }
  html += '<p style="font-size:11px;opacity:.6;margin-top:8px">综合分析，建议选择日干支五行偏「<b style="color:var(--gold)">' + minEle + '</b>」的日期，以补益整体五行平衡。</p>';
  html += '</div>';
  
  html += '</div>';
  
  return html;
}

