    yi: careerScore >= 4 ? ['主动争取项目', '拓展人脉', '学习新技能'] : ['做好本职工作', '维护人际关系', '积累经验'],
    ji: careerScore >= 4 ? ['骄傲自满', '忽视细节'] : ['跳槽转行', '与上级冲突', '盲目扩张'],
