    yi: wealthScore >= 4 ? ['稳健投资', '拓展副业', '理财规划'] : ['储蓄为主', '避免借贷', '控制开支'],
    ji: wealthScore >= 4 ? ['贪婪冒进', '盲目跟风'] : ['高风险投资', '大额借贷', '担保他人'],
    keyMonths: wealthScore >= 4 ? [4, 8, 11] : [1, 5, 10]
