// ═══════════════════════════════════════════════════════════
//  六十甲子周期推算引擎
// ═══════════════════════════════════════════════════════════

// --- 六十甲子常数 ---
var JIAZI_60 = [
  '甲子','乙丑','丙寅','丁卯','戊辰','己巳','庚午','辛未','壬申','癸酉',
  '甲戌','乙亥','丙子','丁丑','戊寅','己卯','庚辰','辛巳','壬午','癸未',
  '甲申','乙酉','丙戌','丁亥','戊子','己丑','庚寅','辛卯','壬辰','癸巳',
  '甲午','乙未','丙申','丁酉','戊戌','己亥','庚子','辛丑','壬寅','癸卯',
  '甲辰','乙巳','丙午','丁未','戊申','己酉','庚戌','辛亥','壬子','癸丑',
  '甲寅','乙卯','丙辰','丁巳','戊午','己未','庚申','辛酉','壬戌','癸亥'
];

// 纳音五行全表（30组对，每组对应2个干支）
var NAYIN_30 = [
  '海中金','海中金','炉中火','炉中火','大林木','大林木',
  '路旁土','路旁土','剑锋金','剑锋金','山头火','山头火',
  '涧下水','涧下水','城头土','城头土','白蜡金','白蜡金',
  '杨柳木','杨柳木','泉中水','泉中水','屋上土','屋上土',
  '霹雳火','霹雳火','松柏木','松柏木','长流水','长流水',
  '沙中金','沙中金','山下火','山下火','平地木','平地木',
  '壁上土','壁上土','金箔金','金箔金','覆灯火','覆灯火',
  '天河水','天河水','大驿土','大驿土','钗钏金','钗钏金',
  '桑柘木','桑柘木','大溪水','大溪水','沙中土','沙中土',
  '天上火','天上火','石榴木','石榴木','大海水','大海水'
];

// 纳音五行所属正五行
var NAYIN_WUXING = {
  '海中金':'金','炉中火':'火','大林木':'木','路旁土':'土','剑锋金':'金',
  '山头火':'火','涧下水':'水','城头土':'土','白蜡金':'金','杨柳木':'木',
  '泉中水':'水','屋上土':'土','霹雳火':'火','松柏木':'木','长流水':'水',
  '沙中金':'金','山下火':'火','平地木':'木','壁上土':'土','金箔金':'金',
  '覆灯火':'火','天河水':'水','大驿土':'土','钗钏金':'金','桑柘木':'木',
  '大溪水':'水','沙中土':'土','天上火':'火','石榴木':'木','大海水':'水'
};

// 地支六冲
var ZHI_CHONG = [
  {a:'子',b:'午'},{a:'丑',b:'未'},{a:'寅',b:'申'},
  {a:'卯',b:'酉'},{a:'辰',b:'戌'},{a:'巳',b:'亥'}
];
// 地支六合
var ZHI_LIUHE = [
  {a:'子',b:'丑'},{a:'寅',b:'亥'},{a:'卯',b:'戌'},
  {a:'辰',b:'酉'},{a:'巳',b:'申'},{a:'午',b:'未'}
];
// 地支三合局
var ZHI_SANHE = [
  ['申','子','辰'],['亥','卯','未'],['寅','午','戌'],['巳','酉','丑']
];

/**
 * 计算某一年的天干地支（基于60甲子循环）
 * 以1984年甲子年为基准
 */
function getYearGanZhiSimple(year) {
  var offset = year - 1984; // 1984 = 甲子年
  var stemIdx = ((offset % 10) + 10) % 10;
  var branchIdx = ((offset % 12) + 12) % 12;
  return { stem: STEMS[stemIdx], branch: BRANCHES[branchIdx], stemIdx: stemIdx, branchIdx: branchIdx };
}

/**
 * 获取某年所在甲子周期的起始年份
 * 1984年是第79个甲子周期的起点（甲子年）
 * 甲子周期序号从1开始计
 */
function getJiaziCycleStart(year) {
  // 找到 <= year 的最近的甲子年
  var offset = year - 1984;
  var cycleOffset = Math.floor(offset / 60);
  var startYear = 1984 + cycleOffset * 60;
  var cycleNum = 79 + cycleOffset; // 1984 = 第79个甲子
  return { startYear: startYear, cycleNum: cycleNum };
}

/**
 * 获取干支在六十甲子中的序号(0-59)
 */
function getJiaziIndex(stem, branch) {
  var sIdx = STEMS.indexOf(stem);
  var bIdx = BRANCHES.indexOf(branch);
  if (sIdx < 0 || bIdx < 0) return -1;
  // 六十甲子：序号n满足 n%10=sIdx, n%12=bIdx
  for (var n = 0; n < 60; n++) {
    if (n % 10 === sIdx && n % 12 === bIdx) return n;
  }
  return -1;
}

/**
 * 获取干支的纳音五行
 */
function getNayinFive(stem, branch) {
  var idx = getJiaziIndex(stem, branch);
  if (idx < 0 || idx >= NAYIN_30.length) return '';
  return NAYIN_30[idx];
}

/**
 * 判断两个地支是否相冲
 */
function isBranchChong(b1, b2) {
  for (var i = 0; i < ZHI_CHONG.length; i++) {
    if ((ZHI_CHONG[i].a === b1 && ZHI_CHONG[i].b === b2) ||
        (ZHI_CHONG[i].a === b2 && ZHI_CHONG[i].b === b1)) return true;
  }
  return false;
}

/**
 * 判断两个地支是否六合
 */
function isBranchLiuhe(b1, b2) {
  for (var i = 0; i < ZHI_LIUHE.length; i++) {
    if ((ZHI_LIUHE[i].a === b1 && ZHI_LIUHE[i].b === b2) ||
        (ZHI_LIUHE[i].a === b2 && ZHI_LIUHE[i].b === b1)) return true;
  }
  return false;
}

/**
 * 判断地支是否在三合局中
 */
function getSanheRelation(b1, b2) {
  for (var i = 0; i < ZHI_SANHE.length; i++) {
    if (ZHI_SANHE[i].indexOf(b1) >= 0 && ZHI_SANHE[i].indexOf(b2) >= 0 && b1 !== b2) {
      return ZHI_SANHE[i].join('');
    }
  }
  return '';
}

/**
 * 天干相冲判断
 */
function isStemChong(s1, s2) {
  for (var i = 0; i < GAN_CHONG_PAIRS.length; i++) {
    if ((GAN_CHONG_PAIRS[i].a === s1 && GAN_CHONG_PAIRS[i].b === s2) ||
        (GAN_CHONG_PAIRS[i].a === s2 && GAN_CHONG_PAIRS[i].b === s1)) return true;
  }
  return false;
}

/**
 * 天干相合判断
 */
function getStemHe(s1, s2) {
  var key = s1 + s2;
  if (GAN_HE[key]) return GAN_HE[key];
  return '';
}

/**
 * 计算流年评分
 * 基于流年天干十神、流年地支与日支关系、纳音五行
 */
function scoreLiunian(yearStem, yearBranch, dayStem, dayBranch, xiEle) {
  var score = 50; // 基础分
  var details = [];

  // 1. 流年天干十神
  var tenGod = getTenGod(yearStem, null, dayStem);
  var dayEle = ELE[dayStem];
  var yearStemEle = ELE[yearStem];

  // 十神评分
  var tgScore = {
    '比肩': 5, '劫财': 0, '食神': 8, '伤官': 3,
    '偏财': 6, '正财': 10, '七杀': -8, '正官': 7,
    '偏印': -3, '正印': 8
  };
  if (tgScore[tenGod] !== undefined) {
    score += tgScore[tenGod];
    details.push('天干' + tenGod + (tgScore[tenGod] >= 0 ? '+' : '') + tgScore[tenGod]);
  }

  // 喜用神加成
  if (yearStemEle === xiEle) {
    score += 10;
    details.push('天干为喜用+' + 10);
  }

  // 2. 流年地支与日支关系
  var yearBranchEle = ZHI_ELE[yearBranch];
  if (yearBranch === dayBranch) {
    score += 5;
    details.push('地支同日支+5');
  }
  if (isBranchChong(yearBranch, dayBranch)) {
    score -= 15;
    details.push('地支冲日支-15');
  }
  if (isBranchLiuhe(yearBranch, dayBranch)) {
    score += 8;
    details.push('地支合日支+8');
  }
  var sanhe = getSanheRelation(yearBranch, dayBranch);
  if (sanhe) {
    score += 6;
    details.push('地支三合(' + sanhe + ')+6');
  }
  if (yearBranchEle === xiEle) {
    score += 8;
    details.push('地支为喜用+8');
  }
  // 地支五行生克
  if (yearBranchEle === getSheng(dayEle)) {
    score += 4;
    details.push('地支生日主+4');
  }
  if (yearBranchEle === getKe(dayEle)) {
    score -= 6;
    details.push('地支克日主-6');
  }

  // 3. 纳音五行
  var nayin = getNayinFive(yearStem, yearBranch);
  var nayinEle = NAYIN_WUXING[nayin] || '';
  if (nayinEle === xiEle) {
    score += 5;
    details.push('纳音' + nayin + '为喜用+5');
  }
  if (nayinEle === dayEle) {
    score += 3;
    details.push('纳音同日主五行+3');
  }

  // 限制范围
  score = Math.max(0, Math.min(100, score));
  return { score: score, tenGod: tenGod, nayin: nayin, details: details };
}

/**
 * 评级
 */
function scoreToGrade(score) {
  if (score >= 80) return '大吉';
  if (score >= 65) return '吉';
  if (score >= 45) return '平';
  if (score >= 30) return '小凶';
  return '凶';
}

function gradeToColor(grade) {
  switch(grade) {
    case '大吉': return '#e74c3c';
    case '吉': return '#e67e22';
    case '平': return '#95a5a6';
    case '小凶': return '#3498db';
    case '凶': return '#2c3e50';
    default: return '#95a5a6';
  }
}

/**
 * 获取关键年份标记
 */
function getKeyYearTags(yearGanZhi, birthGanZhi, dayBranch) {
  var tags = [];
  // 本命年（年柱相同干支）
  if (yearGanZhi.stem === birthGanZhi.stem && yearGanZhi.branch === birthGanZhi.branch) {
    tags.push({ type: 'benming', label: '本命年', color: '#e74c3c' });
  }
  // 冲太岁（年支与年柱地支相冲）
  if (isBranchChong(yearGanZhi.branch, birthGanZhi.branch)) {
    tags.push({ type: 'chong', label: '冲太岁', color: '#e67e22' });
  }
  // 合太岁（年支与年柱地支六合）
  if (isBranchLiuhe(yearGanZhi.branch, birthGanZhi.branch)) {
    tags.push({ type: 'he', label: '合太岁', color: '#27ae60' });
  }
  // 天克地冲（天干相冲+地支相冲）
  if (isStemChong(yearGanZhi.stem, birthGanZhi.stem) && isBranchChong(yearGanZhi.branch, birthGanZhi.branch)) {
    tags.push({ type: 'tianke', label: '天克地冲', color: '#8e44ad' });
  }
  return tags;
}

/**
 * 六十甲子周期推算主函数
 */
function computeJiaziCycle(name, sex, birthYear, birthMonth, birthDay, birthHour) {
  // 获取八字数据
  var baziData = getBaziCalcData(birthYear, birthMonth, birthDay, birthHour || 12, sex);
  if (!baziData || !baziData.pillars) {
    return { success: false, message: '八字数据获取失败' };
  }

  var dayStem = baziData.dayStem;
  var dayBranch = baziData.dayBranch;
  var dayStemIdx = baziData.dayStemIdx;
  var xiEle = baziData.xiEle || ELE[dayStem];
  var dayEle = ELE[dayStem];

  // 出生年干支
  var birthYearGZ = getYearGanZhi(birthYear);
  var birthGanZhi = { stem: baziData.pillars[0].stem, branch: baziData.pillars[0].branch };

  // 当前年份
  var currentYear = new Date().getFullYear();
  var currentGZ = getYearGanZhi(currentYear);

  // ═══ A. 缘主甲子定位 ═══
  var jiaziStart = getJiaziCycleStart(birthYear);
  var birthPosInCycle = birthYear - jiaziStart.startYear; // 0-based
  var currentJiaziStart = getJiaziCycleStart(currentYear);
  var currentPosInCycle = currentYear - currentJiaziStart.startYear;

  var positioning = {
    birthYear: birthYear,
    birthGanZhi: birthGanZhi.stem + birthGanZhi.branch,
    jiaziCycleNum: jiaziStart.cycleNum,
    jiaziStartYear: jiaziStart.startYear,
    jiaziEndYear: jiaziStart.startYear + 59,
    birthPosInCycle: birthPosInCycle + 1,
    currentYear: currentYear,
    currentGanZhi: currentGZ.stem + currentGZ.branch,
    currentJiaziCycleNum: currentJiaziStart.cycleNum,
    currentPosInCycle: currentPosInCycle + 1
  };

  // ═══ B. 六十甲子运势全图 ═══
  var fortuneMap = [];
  for (var i = 0; i < 60; i++) {
    var gz = JIAZI_60[i];
    var yStem = gz[0];
    var yBranch = gz[1];
    var yearAbsolute = jiaziStart.startYear + i;
    var age = yearAbsolute - birthYear;

    var scoreResult = scoreLiunian(yStem, yBranch, dayStem, dayBranch, xiEle);
    var grade = scoreToGrade(scoreResult.score);
    var tags = getKeyYearTags(
      { stem: yStem, branch: yBranch },
      birthGanZhi,
      dayBranch
    );

    fortuneMap.push({
      jiaziIdx: i,
      ganZhi: gz,
      year: yearAbsolute,
      age: age,
      score: scoreResult.score,
      grade: grade,
      tenGod: scoreResult.tenGod,
      nayin: scoreResult.nayin,
      tags: tags,
      details: scoreResult.details
    });
  }

  // ═══ C. 周期对比分析 ═══
  var cycleComparison = [];
  for (var i = 0; i < 60; i++) {
    var thisYear2 = jiaziStart.startYear + i;
    var prevYear = thisYear2 - 60;
    var age2 = thisYear2 - birthYear;
    if (age2 < 0) continue; // 未出生的年份跳过

    var thisGZ = JIAZI_60[i];
    var prevScore = scoreLiunian(thisGZ[0], thisGZ[1], dayStem, dayBranch, xiEle);
    var prevGrade = scoreToGrade(prevScore.score);

    var advice = '';
    if (prevGrade === '大吉' || prevGrade === '吉') {
      advice = '上轮甲子此干支年运势' + prevGrade + '，本轮类似气场再现，宜把握机遇、顺势而为。';
    } else if (prevGrade === '凶') {
      advice = '上轮甲子此干支年运势' + prevGrade + '，本轮需提前防范，注意健康与人际关系。';
    } else if (prevGrade === '小凶') {
      advice = '上轮甲子此干支年运势' + prevGrade + '，本轮宜稳中求进，避免冒进。';
    } else {
      advice = '上轮甲子此干支年运势平稳，本轮可在此基调上规划发展。';
    }

    cycleComparison.push({
      ganZhi: thisGZ,
      year: thisYear2,
      prevYear: prevYear,
      age: age2,
      prevGrade: prevGrade,
      advice: advice
    });
  }

  // ═══ D. 人生大运甲子映射 ═══
  var dayun = baziData.dayun || [];
  var dayunMapping = [];
  for (var i = 0; i < dayun.length; i++) {
    var dy = dayun[i];
    if (!dy.gan || !dy.zhi) continue;
    var dyGz = dy.gan + dy.zhi;
    var dyJiaziIdx = JIAZI_60.indexOf(dyGz);
    var dyScore = scoreLiunian(dy.gan, dy.zhi, dayStem, dayBranch, xiEle);
    var dyGrade = scoreToGrade(dyScore.score);
    var resonance = '';
    if (dyScore.score >= 65) {
      resonance = '大运与日主共振良好，此阶段运势上行，宜积极进取。';
    } else if (dyScore.score >= 45) {
      resonance = '大运与日主关系平稳，宜守成发展、蓄势待发。';
    } else {
      resonance = '大运与日主有冲克，此阶段需谨慎行事、以退为进。';
    }
    dayunMapping.push({
      index: dy.index,
      ganZhi: dyGz,
      ageStart: dy.ageStart,
      ageEnd: dy.ageEnd,
      yearStart: dy.yearStart,
      yearEnd: dy.yearEnd,
      jiaziIdx: dyJiaziIdx,
      jiaziPos: dyJiaziIdx >= 0 ? (dyJiaziIdx + 1) : -1,
      grade: dyGrade,
      score: dyScore.score,
      tenGod: dyScore.tenGod,
      resonance: resonance
    });
  }

  // ═══ E. 关键年份预警 ═══
  var warnings = [];

  // 本命年：年龄12/24/36/48/60
  var benmingAges = [12, 24, 36, 48, 60];
  for (var i = 0; i < benmingAges.length; i++) {
    var age3 = benmingAges[i];
    var yr = birthYear + age3;
    warnings.push({
      type: '本命年',
      age: age3,
      year: yr,
      ganZhi: getYearGanZhi(yr).stem + getYearGanZhi(yr).branch,
      note: '本命年值太岁，运势波动较大。注意健康、避免重大变动。',
      resolve: '佩戴本命年吉祥物（红绳/太岁符），行善积德，避免冲犯太岁。'
    });
  }

  // 冲太岁年：遍历60甲子找年支与出生年支相冲的年份
  var birthBranch = birthGanZhi.branch;
  for (var i = 0; i < ZHI_CHONG_PAIRS.length; i++) {
    var chongBranch = '';
    if (ZHI_CHONG_PAIRS[i].a === birthBranch) chongBranch = ZHI_CHONG_PAIRS[i].b;
    if (ZHI_CHONG_PAIRS[i].b === birthBranch) chongBranch = ZHI_CHONG_PAIRS[i].a;
    if (!chongBranch) continue;
    for (var n = 0; n < 60; n++) {
      var gz = JIAZI_60[n];
      if (gz[1] === chongBranch) {
        var yr = jiaziStart.startYear + n;
        var age3 = yr - birthYear;
        if (age3 > 0 && age3 <= 80) {
          warnings.push({
            type: '冲太岁',
            age: age3,
            year: yr,
            ganZhi: getYearGanZhi(yr).stem + getYearGanZhi(yr).branch,
            note: '冲太岁年，变动频繁。可能涉及搬家、转学、换工作等。',
            resolve: '提前规划，主动求变以化解被动冲击。佩戴相合生肖吉祥物。'
          });
        }
      }
    }
  }

  // 合太岁年
  var birthBranchIdx = BRANCHES.indexOf(birthGanZhi.branch);
  for (var i = 0; i < ZHI_LIUHE.length; i++) {
    var heBranch = '';
    if (ZHI_LIUHE[i].a === birthGanZhi.branch) heBranch = ZHI_LIUHE[i].b;
    if (ZHI_LIUHE[i].b === birthGanZhi.branch) heBranch = ZHI_LIUHE[i].a;
    if (!heBranch) continue;
    // 找到合太岁的年份（在第一个60年内）
    for (var n = 0; n < 60; n++) {
      var gz = JIAZI_60[n];
      if (gz[1] === heBranch) {
        var yr = jiaziStart.startYear + n;
        var age3 = yr - birthYear;
        if (age3 > 0 && age3 <= 80) {
          warnings.push({
            type: '合太岁',
            age: age3,
            year: yr,
            ganZhi: gz,
            note: '合太岁年，人际关系和谐，贵人相助。运势相对顺畅。',
            resolve: '把握机遇，拓展人脉，适合合作、谈判、婚嫁。'
          });
        }
      }
    }
  }

  // 天克地冲年（天干相冲+地支相冲）
  var birthStemIdx2 = STEMS.indexOf(birthGanZhi.stem);
  var birthBranchIdx2 = BRANCHES.indexOf(birthGanZhi.branch);
  for (var n = 0; n < 60; n++) {
    var gz = JIAZI_60[n];
    var yStem = gz[0], yBranch = gz[1];
    if (isStemChong(yStem, birthGanZhi.stem) && isBranchChong(yBranch, birthGanZhi.branch)) {
      var yr = jiaziStart.startYear + n;
      var age3 = yr - birthYear;
      if (age3 > 0 && age3 <= 80) {
        warnings.push({
          type: '天克地冲',
          age: age3,
          year: yr,
          ganZhi: gz,
          note: '天克地冲年，天地皆冲，运势剧变。须防意外、破财、健康问题。',
          resolve: '此年宜静不宜动，避免投资、远行。祈福禳灾，行善化解。'
        });
      }
    }
  }

  // 按年龄排序
  warnings.sort(function(a, b) { return a.age - b.age; });

  // ═══ F. 纳音五行分析 ═══
  var birthNayin = getNayinFive(birthGanZhi.stem, birthGanZhi.branch);
  var birthNayinEle = NAYIN_WUXING[birthNayin] || '';
  var dayNayin = getNayinFive(dayStem, dayBranch);
  var dayNayinEle = NAYIN_WUXING[dayNayin] || '';

  // 纳音五行与正五行关系
  var nayinRelation = '';
  if (birthNayinEle === dayEle) {
    nayinRelation = '出生年纳音五行与日主五行相同，命局根基稳固，先天禀赋充足。';
  } else if (birthNayinEle === getSheng(dayEle)) {
    nayinRelation = '出生年纳音五行生日主五行，得先天之助，贵人运佳。';
  } else if (birthNayinEle === getKe(dayEle)) {
    nayinRelation = '出生年纳音五行克日主五行，先天有压制，需后天化解。';
  } else if (dayEle === getSheng(birthNayinEle)) {
    nayinRelation = '日主五行生出生年纳音五行，泄秀之象，才华外露但需注意精力分配。';
  } else if (dayEle === getKe(birthNayinEle)) {
    nayinRelation = '日主五行克出生年纳音五行，有开创之力，但需注意收敛。';
  } else {
    nayinRelation = '出生年纳音五行与日主五行关系中和，无明显生克。';
  }

  var nayinAnalysis = {
    birthNayin: birthNayin,
    birthNayinEle: birthNayinEle,
    dayNayin: dayNayin,
    dayNayinEle: dayNayinEle,
    nayinRelation: nayinRelation,
    nayinTable: JIAZI_60.map(function(gz, i) {
      return { ganZhi: gz, nayin: NAYIN_30[i], nayinEle: NAYIN_WUXING[NAYIN_30[i]] || '' };
    })
  };

  // ═══ G. 长期规划建议 ═══
  var phases = [];
  for (var i = 0; i < 6; i++) {
    var ageStart = i * 10;
    var ageEnd = (i + 1) * 10 - 1;
    var yrStart = birthYear + ageStart;
    var yrEnd = birthYear + ageEnd;

    // 计算这10年的平均分
    var totalScore = 0, count = 0;
    var keyEvents = [];
    for (var a = ageStart; a <= ageEnd && a < 80; a++) {
      var yr = birthYear + a;
      var jiaziIdx2 = (yr - jiaziStart.startYear + 600) % 60;
      if (jiaziIdx2 >= 0 && jiaziIdx2 < 60) {
        var fm = fortuneMap[jiaziIdx2];
        if (fm) {
          totalScore += fm.score;
          count++;
          if (fm.grade === '大吉' || fm.grade === '凶') {
            keyEvents.push({ age: a, year: yr, grade: fm.grade, ganZhi: fm.ganZhi });
          }
        }
      }
    }
    var avgScore = count > 0 ? Math.round(totalScore / count) : 50;
    var phaseType = '';
    var phaseAdvice = '';
    if (avgScore >= 70) {
      phaseType = '上升期';
      phaseAdvice = '此阶段运势上扬，适合创业、拓展、进取。把握机遇，大胆前行。';
    } else if (avgScore >= 55) {
      phaseType = '平稳发展期';
      phaseAdvice = '此阶段运势平稳，适合守业、学习、积累。稳扎稳打，厚积薄发。';
    } else if (avgScore >= 40) {
      phaseType = '调整期';
      phaseAdvice = '此阶段运势起伏，宜调整心态、蓄势待发。学习充电，等待时机。';
    } else {
      phaseType = '低谷期';
      phaseAdvice = '此阶段运势偏低，宜保守行事、修身养性。避免冒进，注意健康。';
    }

    // 特殊建议
    var specialAdvice = '';
    if (ageStart === 0) {
      specialAdvice = '幼年成长期，重在家庭教育与性格塑造。';
    } else if (ageStart === 10) {
      specialAdvice = '求学关键期，专注学业，培养兴趣特长。';
    } else if (ageStart === 20) {
      specialAdvice = '事业起步期，适合学习技能、积累经验。创业需谨慎。';
    } else if (ageStart === 30) {
      specialAdvice = '事业黄金期，适合创业、晋升、置业。婚恋宜把握。';
    } else if (ageStart === 40) {
      specialAdvice = '人生中场，适合守业深耕、健康管理。投资宜稳健。';
    } else if (ageStart === 50) {
      specialAdvice = '收获期，适合传承经验、关注健康、规划晚年。';
    }

    phases.push({
      ageRange: ageStart + '-' + ageEnd + '岁',
      yearRange: yrStart + '-' + yrEnd,
      avgScore: avgScore,
      phaseType: phaseType,
      phaseAdvice: phaseAdvice,
      specialAdvice: specialAdvice,
      keyEvents: keyEvents
    });
  }

  // 适合搬家/置业/投资的年份
  var favorableYears = [];
  for (var i = 0; i < fortuneMap.length; i++) {
    var fm = fortuneMap[i];
    if (fm.age < 18 || fm.age > 75) continue;
    if (fm.grade === '大吉' || fm.grade === '吉') {
      var suggestions = [];
      if (fm.tenGod === '正财' || fm.tenGod === '偏财') {
        suggestions.push('投资理财');
      }
      if (fm.tenGod === '正印' || fm.tenGod === '偏印') {
        suggestions.push('置业安居');
      }
      if (fm.tags.some(function(t) { return t.type === 'he'; })) {
        suggestions.push('搬家迁居');
      }
      if (fm.tenGod === '正官' || fm.tenGod === '七杀') {
        suggestions.push('事业晋升');
      }
      if (suggestions.length > 0) {
        favorableYears.push({
          age: fm.age,
          year: fm.year,
          ganZhi: fm.ganZhi,
          grade: fm.grade,
          suggestions: suggestions
        });
      }
    }
  }

  var longTermPlan = {
    phases: phases,
    favorableYears: favorableYears.slice(0, 15) // 限制数量
  };

  // ═══ H. 三元九运交叉分析 ═══
  var sanyuanCross = (function() {
    var birthYY = getCurrentYuanYun(birthYear);
    var curYY = getCurrentYuanYun(currentYear);
    var dayMasterFull = _getDayMasterFull(dayStem);
    var dayEle2 = ELE[dayStem] || '木';

    // 甲子60年与三元九运的关系：一个甲子60年覆盖3运（每运20年）
    var jiaziYunMap = [];
    for (var sy = 0; sy < 3; sy++) {
      var segStartYear = jiaziStart.startYear + sy * 20;
      var segEndYear = segStartYear + 19;
      var segYY = getCurrentYuanYun(segStartYear);
      var segData = SANYUAN_JIUYUN[segYY.yun];
      jiaziYunMap.push({
        segment: (sy + 1) + '/3',
        yearRange: segStartYear + '-' + segEndYear,
        ageRange: (sy * 20) + '-' + (sy * 20 + 19) + '岁',
        yunName: segYY.name,
        yunStar: segYY.star,
        yunWuxing: segYY.wuxing,
        yunDirection: segYY.direction,
        characteristics: segData ? segData.characteristics : '',
        industries: segData ? segData.industries : ''
      });
    }

    // 大运交接与运星交替的共振效应
    var resonanceEffects = [];
    for (var di = 0; di < dayunMapping.length; di++) {
      var dm = dayunMapping[di];
      if (!dm.yearStart) continue;
      var dmYY = getCurrentYuanYun(dm.yearStart);
      var dmRel = _sanyuanWxRelation(dayEle2, dmYY.wuxing);
      var relDesc = '';
      if (dmRel === '生我') relDesc = '大运起时处于' + dmYY.name + '，运星生扶日主，大吉';
      else if (dmRel === '我生') relDesc = '大运起时处于' + dmYY.name + '，日主泄于运星，需注意精力';
      else if (dmRel === '克我') relDesc = '大运起时处于' + dmYY.name + '，运星克日主，压力较大';
      else if (dmRel === '我克') relDesc = '大运起时处于' + dmYY.name + '，日主克运星为财，财运旺';
      else relDesc = '大运起时处于' + dmYY.name + '，比和稳固';
      // 检查大运期间是否有运星交替
      var midYear = Math.floor((dm.yearStart + dm.yearEnd) / 2);
      var startYun = getCurrentYuanYun(dm.yearStart).yun;
      var endYun = getCurrentYuanYun(dm.yearEnd).yun;
      if (startYun !== endYun) {
        relDesc += '；此大运期间经历运星交替(' + getCurrentYuanYun(dm.yearStart).name + '→' + getCurrentYuanYun(dm.yearEnd).name + ')，需顺势调整方向';
      }
      resonanceEffects.push({
        dayun: dm.ganZhi,
        ageRange: dm.ageStart + '-' + dm.ageEnd + '岁',
        yearRange: dm.yearStart + '-' + dm.yearEnd,
        yunAtStart: dmYY.name,
        relation: relDesc
      });
    }

    // 九紫离火运对各日主的影响
    var jiuZhiImpact = {
      '木': '木生火，付出多但有为，宜文化教育行业。注意精力消耗，宜补水养木',
      '火': '火火相助，事业旺但防过燥，宜科技能源行业。当令者更需收敛锋芒',
      '土': '火生土，得助力贵人多，宜地产农业。火生土为贵人运，大胆推进',
      '金': '火克金，压力大需谨慎，宜守不宜攻。学会减压，培养柔性沟通',
      '水': '水克火，可掌控但防过劳，宜物流贸易。水克火为财，是九运中最有机会的日主之一'
    };
    var dayImpact = jiuZhiImpact[dayEle2] || '关系平和，顺势而为';

    // 催旺方位与化解建议
    var cuiwangDir = '九紫位正南方（宜催旺）：放置红色/紫色饰品、紫水晶、红玛瑙';
    var huajieDir = '正北方为零神位（宜化解）：放置黑曜石、金属饰品化煞';

    // 运星交替时间线（缘主一生会经历的运星）
    var yunTimeline = [];
    var lifeEndYear = birthYear + 100;
    for (var yr = birthYear; yr <= lifeEndYear; yr += 20) {
      var yy2 = getCurrentYuanYun(yr);
      var ageAtYun = yr - birthYear;
      // 找到运星交替的年份（每20年一次）
      if (ageAtYun >= 0) {
        var prevYun = yr > birthYear ? getCurrentYuanYun(yr - 1) : null;
        var isTransition = prevYun && prevYun.yun !== yy2.yun;
        yunTimeline.push({
          year: yr,
          age: ageAtYun,
          yunName: yy2.name,
          yunStar: yy2.star,
          yunWuxing: yy2.wuxing,
          yunDirection: yy2.direction,
          isTransition: isTransition,
          prevYunName: prevYun ? prevYun.name : null
        });
      }
    }

    return {
      birthYuanYun: {
        name: birthYY.name,
        yuan: birthYY.yuan,
        star: birthYY.star,
        wuxing: birthYY.wuxing,
        direction: birthYY.direction,
        period: birthYY.periodInThisCycle
      },
      currentYuanYun: {
        name: curYY.name,
        yuan: curYY.yuan,
        star: curYY.star,
        wuxing: curYY.wuxing,
        direction: curYY.direction,
        period: curYY.periodInThisCycle,
        yunYear: curYY.yunYear
      },
      jiaziYunMap: jiaziYunMap,
      resonanceEffects: resonanceEffects,
      dayMasterImpact: dayImpact,
      cuiwangDirection: cuiwangDir,
      huajieDirection: huajieDir,
      yunTimeline: yunTimeline,
      dayMasterFull: dayMasterFull,
      dayEle: dayEle2
    };
  })();

  // ═══ 组装报告 ═══
  return {
    success: true,
    name: name || '缘主',
    sex: sex,
    birthDate: birthYear + '年' + birthMonth + '月' + birthDay + '日',
    birthHour: birthHour,
    dayStem: dayStem,
    dayBranch: dayBranch,
    dayMaster: baziData.dayMaster,
    xiEle: xiEle,
    positioning: positioning,
    fortuneMap: fortuneMap,
    cycleComparison: cycleComparison,
    dayunMapping: dayunMapping,
    warnings: warnings,
    nayinAnalysis: nayinAnalysis,
    longTermPlan: longTermPlan,
    sanyuanCross: sanyuanCross
  };
}

/**
 * 渲染六十甲子周期报告为HTML
 */
function renderJiaziCycleReport(data) {
  if (!data || !data.success) {
    return '<div style="color:#e74c3c;padding:20px">' + (data && data.message ? data.message : '推算失败') + '</div>';
  }

  var html = '';
  var gold = 'var(--gold)';
  var gold2 = 'var(--gold2)';
  var ink = 'var(--ink)';
  var paper = 'var(--paper)';
  var paper2 = 'var(--paper2)';

  // 标题
  html += '<div class="result-banner" style="background:linear-gradient(135deg,rgba(201,168,76,0.12),rgba(201,168,76,0.04));border:1px solid rgba(201,168,76,0.3);border-radius:14px;padding:20px;margin-bottom:20px">';
  html += '<div style="font-size:22px;color:' + gold + ';font-weight:bold;letter-spacing:4px;margin-bottom:8px">🔮 六十甲子周期推算报告</div>';
  html += '<div style="font-size:14px;color:' + paper2 + '">缘主：<b style="color:' + gold + '">' + data.name + '</b> | ' + (data.sex === 'male' ? '男' : '女') + ' | ' + data.birthDate + '</div>';
  html += '<div style="font-size:13px;color:' + paper2 + ';margin-top:4px">日主：<b style="color:' + gold + '">' + data.dayMaster + '</b> | 喜用神：<b style="color:' + gold + '">' + data.xiEle + '</b></div>';
  html += '</div>';

  // ═══ A. 甲子定位 ═══
  var p = data.positioning;
  html += '<div class="analysis-card" style="margin-bottom:16px">';
  html += '<h5 style="color:' + gold + ';font-size:16px;letter-spacing:2px;margin-bottom:12px">📍 甲子定位</h5>';
  html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(200px,1fr));gap:12px">';
  html += '<div style="padding:12px;background:rgba(201,168,76,0.06);border-radius:8px"><div style="font-size:11px;color:' + paper2 + '">出生年干支</div><div style="font-size:18px;color:' + gold + ';font-weight:bold">' + p.birthGanZhi + '</div></div>';
  html += '<div style="padding:12px;background:rgba(201,168,76,0.06);border-radius:8px"><div style="font-size:11px;color:' + paper2 + '">甲子周期</div><div style="font-size:16px;color:' + gold + '">第' + p.jiaziCycleNum + '个甲子</div><div style="font-size:11px;color:' + paper2 + '">' + p.jiaziStartYear + '-' + p.jiaziEndYear + '</div></div>';
  html += '<div style="padding:12px;background:rgba(201,168,76,0.06);border-radius:8px"><div style="font-size:11px;color:' + paper2 + '">缘主在周期中</div><div style="font-size:16px;color:' + gold + '">第' + p.birthPosInCycle + '年</div></div>';
  html += '<div style="padding:12px;background:rgba(201,168,76,0.06);border-radius:8px"><div style="font-size:11px;color:' + paper2 + '">' + p.currentYear + '年当前位置</div><div style="font-size:16px;color:' + gold + '">第' + p.currentPosInCycle + '年</div><div style="font-size:11px;color:' + paper2 + '">' + p.currentGanZhi + '</div></div>';
  html += '</div>';
  html += '</div>';

  // ═══ B. 六十甲子运势全图 ═══
  html += '<div class="analysis-card" style="margin-bottom:16px">';
  html += '<h5 style="color:' + gold + ';font-size:16px;letter-spacing:2px;margin-bottom:12px">📊 六十甲子运势全图</h5>';
  html += '<div style="display:grid;grid-template-columns:repeat(10,1fr);gap:4px;margin-bottom:12px">';
  for (var i = 0; i < data.fortuneMap.length; i++) {
    var fm = data.fortuneMap[i];
    var color = gradeToColor(fm.grade);
    var tagHtml = '';
    for (var t = 0; t < fm.tags.length; t++) {
      tagHtml += '<div style="font-size:9px;color:' + fm.tags[t].color + ';margin-top:2px">' + fm.tags[t].label + '</div>';
    }
    html += '<div style="text-align:center;padding:6px 2px;background:rgba(201,168,76,0.04);border-radius:4px;cursor:default;min-height:60px" title="' + fm.ganZhi + ' ' + fm.grade + ' (分数:' + fm.score + ')">';
    html += '<div style="font-size:12px;color:' + color + ';font-weight:bold">' + fm.ganZhi + '</div>';
    html += '<div style="font-size:9px;color:' + paper2 + '">' + (fm.age >= 0 ? fm.age + '岁' : '未生') + '</div>';
    html += '<div style="width:8px;height:8px;border-radius:50%;background:' + color + ';margin:2px auto"></div>';
    html += tagHtml;
    html += '</div>';
  }
  html += '</div>';
  // 图例
  html += '<div style="display:flex;gap:16px;justify-content:center;font-size:12px;color:' + paper2 + ';flex-wrap:wrap">';
  var grades = ['大吉','吉','平','小凶','凶'];
  for (var g = 0; g < grades.length; g++) {
    html += '<span style="display:flex;align-items:center;gap:4px"><span style="width:10px;height:10px;border-radius:50%;background:' + gradeToColor(grades[g]) + '"></span>' + grades[g] + '</span>';
  }
  html += '</div>';
  // 关键年份列表
  html += '<details style="margin-top:12px"><summary style="cursor:pointer;color:' + gold + ';font-size:13px">📋 查看逐年详细评分</summary>';
  html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(180px,1fr));gap:6px;margin-top:8px">';
  for (var i = 0; i < data.fortuneMap.length; i++) {
    var fm = data.fortuneMap[i];
    if (fm.age < 0) continue;
    var color = gradeToColor(fm.grade);
    var tagStr = fm.tags.map(function(t) { return t.label; }).join(' ') || '';
    html += '<div style="padding:6px 8px;background:rgba(201,168,76,0.04);border-radius:6px;font-size:12px">';
    html += '<span style="color:' + color + ';font-weight:bold">' + fm.ganZhi + '</span> ';
    html += '<span style="color:' + paper2 + '">' + fm.age + '岁(' + fm.year + ')</span> ';
    html += '<span style="color:' + color + '">' + fm.grade + '</span> ';
    html += '<span style="color:' + paper2 + ';font-size:11px">' + fm.tenGod + '</span>';
    if (tagStr) html += '<span style="color:#e74c3c;font-size:10px;margin-left:4px">[' + tagStr + ']</span>';
    html += '</div>';
  }
  html += '</div></details>';
  html += '</div>';

  // ═══ C. 周期对比分析 ═══
  html += '<div class="analysis-card" style="margin-bottom:16px">';
  html += '<h5 style="color:' + gold + ';font-size:16px;letter-spacing:2px;margin-bottom:12px">🔄 周期对比分析（60年轮回）</h5>';
  html += '<div style="font-size:13px;color:' + paper2 + ';line-height:1.8;margin-bottom:12px">天理循环，甲子一轮回。上一甲子相同干支年的运势特征，可为本轮提供参考。</div>';
  html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(300px,1fr));gap:8px">';
  for (var i = 0; i < data.cycleComparison.length; i++) {
    var cc = data.cycleComparison[i];
    var color = gradeToColor(cc.prevGrade);
    html += '<div style="padding:10px;background:rgba(201,168,76,0.04);border-left:3px solid ' + color + ';border-radius:6px">';
    html += '<div style="font-size:13px;color:' + gold + ';font-weight:bold">' + cc.ganZhi + ' | ' + cc.age + '岁(' + cc.year + ')</div>';
    html += '<div style="font-size:11px;color:' + paper2 + '">上轮:' + cc.prevYear + '年</div>';
    html += '<div style="font-size:12px;color:' + color + ';margin-top:4px">上轮评级：' + cc.prevGrade + '</div>';
    html += '<div style="font-size:12px;color:' + paper + ';margin-top:4px;line-height:1.6">' + cc.advice + '</div>';
    html += '</div>';
  }
  html += '</div>';
  html += '</div>';

  // ═══ D. 大运甲子映射 ═══
  html += '<div class="analysis-card" style="margin-bottom:16px">';
  html += '<h5 style="color:' + gold + ';font-size:16px;letter-spacing:2px;margin-bottom:12px">🗺️ 人生大运甲子映射</h5>';
  if (data.dayunMapping.length === 0) {
    html += '<div style="color:' + paper2 + '">暂无大运数据</div>';
  } else {
    html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:10px">';
    for (var i = 0; i < data.dayunMapping.length; i++) {
      var dy = data.dayunMapping[i];
      var color = gradeToColor(dy.grade);
      html += '<div style="padding:12px;background:rgba(201,168,76,0.06);border-radius:8px;border-top:3px solid ' + color + '">';
      html += '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px">';
      html += '<span style="font-size:18px;color:' + gold + ';font-weight:bold">' + dy.ganZhi + '</span>';
      html += '<span style="font-size:12px;color:' + color + ';font-weight:bold">' + dy.grade + '</span>';
      html += '</div>';
      html += '<div style="font-size:12px;color:' + paper2 + '">' + dy.ageStart + '-' + dy.ageEnd + '岁 | ' + dy.yearStart + '-' + dy.yearEnd + '年</div>';
      html += '<div style="font-size:11px;color:' + paper2 + ';margin-top:2px">甲子位置：第' + dy.jiaziPos + '/60 | 十神：' + dy.tenGod + '</div>';
      html += '<div style="font-size:12px;color:' + paper + ';margin-top:6px;line-height:1.6">' + dy.resonance + '</div>';
      html += '</div>';
    }
    html += '</div>';
  }
  html += '</div>';

  // ═══ E. 关键年份预警 ═══
  html += '<div class="analysis-card" style="margin-bottom:16px">';
  html += '<h5 style="color:#e74c3c;font-size:16px;letter-spacing:2px;margin-bottom:12px">⚠️ 关键年份预警</h5>';
  html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(320px,1fr));gap:10px">';
  for (var i = 0; i < data.warnings.length; i++) {
    var w = data.warnings[i];
    var bg = '';
    var border = '';
    if (w.type === '本命年') { bg = 'rgba(231,76,60,0.08)'; border = '#e74c3c'; }
    else if (w.type === '冲太岁') { bg = 'rgba(230,126,34,0.08)'; border = '#e67e22'; }
    else if (w.type === '合太岁') { bg = 'rgba(39,174,96,0.08)'; border = '#27ae60'; }
    else if (w.type === '天克地冲') { bg = 'rgba(142,68,173,0.08)'; border = '#8e44ad'; }
    html += '<div style="padding:12px;background:' + bg + ';border-left:3px solid ' + border + ';border-radius:8px">';
    html += '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px">';
    html += '<span style="font-size:14px;color:' + border + ';font-weight:bold">' + w.type + '</span>';
    html += '<span style="font-size:13px;color:' + gold + '">' + w.age + '岁 · ' + w.year + '年</span>';
    html += '</div>';
    html += '<div style="font-size:13px;color:' + gold + ';margin-bottom:4px">' + w.ganZhi + '</div>';
    html += '<div style="font-size:12px;color:' + paper + ';line-height:1.6;margin-bottom:4px">' + w.note + '</div>';
    html += '<div style="font-size:12px;color:' + paper2 + ';line-height:1.6">💡 ' + w.resolve + '</div>';
    html += '</div>';
  }
  html += '</div>';
  html += '</div>';

  // ═══ F. 纳音五行分析 ═══
  var na = data.nayinAnalysis;
  html += '<div class="analysis-card" style="margin-bottom:16px">';
  html += '<h5 style="color:' + gold + ';font-size:16px;letter-spacing:2px;margin-bottom:12px">🎵 纳音五行分析</h5>';
  html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(200px,1fr));gap:12px;margin-bottom:16px">';
  html += '<div style="padding:12px;background:rgba(201,168,76,0.06);border-radius:8px"><div style="font-size:11px;color:' + paper2 + '">出生年纳音</div><div style="font-size:18px;color:' + gold + ';font-weight:bold">' + na.birthNayin + '</div><div style="font-size:12px;color:' + paper2 + '">五行：' + na.birthNayinEle + '</div></div>';
  html += '<div style="padding:12px;background:rgba(201,168,76,0.06);border-radius:8px"><div style="font-size:11px;color:' + paper2 + '">日柱纳音</div><div style="font-size:18px;color:' + gold + ';font-weight:bold">' + na.dayNayin + '</div><div style="font-size:12px;color:' + paper2 + '">五行：' + na.dayNayinEle + '</div></div>';
  html += '</div>';
  html += '<div style="padding:12px;background:rgba(201,168,76,0.04);border-radius:8px;font-size:13px;color:' + paper + ';line-height:1.8;margin-bottom:12px">' + na.nayinRelation + '</div>';
  // 纳音全表
  html += '<details><summary style="cursor:pointer;color:' + gold + ';font-size:13px">📋 六十甲子纳音五行全表</summary>';
  html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(140px,1fr));gap:4px;margin-top:8px">';
  for (var i = 0; i < na.nayinTable.length; i++) {
    var nt = na.nayinTable[i];
    var nayinColor = NAYIN_COLOR[nt.nayin] || gold;
    html += '<div style="padding:6px 8px;background:rgba(201,168,76,0.04);border-radius:4px;text-align:center">';
    html += '<div style="font-size:13px;color:' + gold + ';font-weight:bold">' + nt.ganZhi + '</div>';
    html += '<div style="font-size:12px;color:' + nayinColor + '">' + nt.nayin + '</div>';
    html += '<div style="font-size:10px;color:' + paper2 + '">' + nt.nayinEle + '</div>';
    html += '</div>';
  }
  html += '</div></details>';
  html += '</div>';

  // ═══ G. 长期规划建议 ═══
  var lp = data.longTermPlan;
  html += '<div class="analysis-card" style="margin-bottom:16px">';
  html += '<h5 style="color:' + gold + ';font-size:16px;letter-spacing:2px;margin-bottom:12px">🧭 人生60年长期规划建议</h5>';
  html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(300px,1fr));gap:10px;margin-bottom:16px">';
  for (var i = 0; i < lp.phases.length; i++) {
    var ph = lp.phases[i];
    var phaseColor = '';
    if (ph.phaseType === '上升期') phaseColor = '#e74c3c';
    else if (ph.phaseType === '平稳发展期') phaseColor = '#27ae60';
    else if (ph.phaseType === '调整期') phaseColor = '#e67e22';
    else phaseColor = '#3498db';
    html += '<div style="padding:14px;background:rgba(201,168,76,0.06);border-radius:8px;border-left:4px solid ' + phaseColor + '">';
    html += '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px">';
    html += '<span style="font-size:15px;color:' + gold + ';font-weight:bold">' + ph.ageRange + '</span>';
    html += '<span style="font-size:12px;color:' + phaseColor + ';font-weight:bold;padding:2px 8px;border-radius:10px;background:rgba(201,168,76,0.1)">' + ph.phaseType + '</span>';
    html += '</div>';
    html += '<div style="font-size:11px;color:' + paper2 + ';margin-bottom:6px">' + ph.yearRange + ' | 均分:' + ph.avgScore + '</div>';
    html += '<div style="font-size:12px;color:' + paper + ';line-height:1.6;margin-bottom:4px">' + ph.phaseAdvice + '</div>';
    if (ph.specialAdvice) {
      html += '<div style="font-size:12px;color:' + gold + ';line-height:1.6">💡 ' + ph.specialAdvice + '</div>';
    }
    if (ph.keyEvents.length > 0) {
      html += '<div style="margin-top:6px">';
      for (var k = 0; k < ph.keyEvents.length; k++) {
        var ke = ph.keyEvents[k];
        html += '<span style="font-size:11px;margin-right:6px;color:' + gradeToColor(ke.grade) + '">' + ke.age + '岁' + ke.ganZhi + ke.grade + '</span>';
      }
      html += '</div>';
    }
    html += '</div>';
  }
  html += '</div>';

  // 适宜年份
  if (lp.favorableYears.length > 0) {
    html += '<div style="padding:14px;background:rgba(39,174,96,0.06);border-radius:8px">';
    html += '<div style="font-size:14px;color:#27ae60;font-weight:bold;margin-bottom:8px">✨ 适宜行动年份推荐</div>';
    html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(200px,1fr));gap:6px">';
    for (var i = 0; i < lp.favorableYears.length; i++) {
      var fy = lp.favorableYears[i];
      html += '<div style="padding:8px;background:rgba(255,255,255,0.04);border-radius:6px">';
      html += '<div style="font-size:13px;color:' + gold + ';font-weight:bold">' + fy.age + '岁 · ' + fy.year + '年 ' + fy.ganZhi + '</div>';
      html += '<div style="font-size:11px;color:#27ae60">' + fy.suggestions.join('、') + '</div>';
      html += '</div>';
    }
    html += '</div></div>';
  }
  html += '</div>';

  // ═══ H. 三元九运交叉分析 ═══
  var sc = data.sanyuanCross;
  if (sc) {
    html += '<div class="analysis-card" style="margin-bottom:16px;border:1px solid rgba(231,76,60,0.2)">';
    html += '<h5 style="color:#e74c3c;font-size:16px;letter-spacing:2px;margin-bottom:12px">🔥 三元九运交叉分析</h5>';

    // 出生时与当前运星
    html += '<div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:14px">';
    html += '<div style="padding:12px;background:rgba(72,201,176,0.06);border-radius:8px;border-left:3px solid #48c9b0">';
    html += '<div style="font-size:12px;color:#48c9b0;font-weight:bold;margin-bottom:6px">📍 出生时运星</div>';
    html += '<div style="font-size:14px;color:' + gold + ';font-weight:bold">' + sc.birthYuanYun.name + '</div>';
    html += '<div style="font-size:12px;color:' + paper2 + '">' + sc.birthYuanYun.yuan + ' | ' + sc.birthYuanYun.star + ' | ' + sc.birthYuanYun.wuxing + '行</div>';
    html += '<div style="font-size:11px;color:' + paper2 + '">区间：' + sc.birthYuanYun.period + '</div>';
    html += '</div>';
    html += '<div style="padding:12px;background:rgba(231,76,60,0.06);border-radius:8px;border-left:3px solid #e74c3c">';
    html += '<div style="font-size:12px;color:#e74c3c;font-weight:bold;margin-bottom:6px">📍 当前运星</div>';
    html += '<div style="font-size:14px;color:' + gold + ';font-weight:bold">' + sc.currentYuanYun.name + '</div>';
    html += '<div style="font-size:12px;color:' + paper2 + '">' + sc.currentYuanYun.yuan + ' | ' + sc.currentYuanYun.star + ' | ' + sc.currentYuanYun.wuxing + '行</div>';
    html += '<div style="font-size:11px;color:' + paper2 + '">区间：' + sc.currentYuanYun.period + ' | 第' + sc.currentYuanYun.yunYear + '/20年</div>';
    html += '</div>';
    html += '</div>';

    // 甲子60年与三元九运关系
    html += '<div style="padding:12px;background:rgba(201,168,76,0.04);border-radius:8px;margin-bottom:14px">';
    html += '<div style="font-size:13px;color:' + gold + ';font-weight:bold;margin-bottom:8px">🗺️ 甲子60年与三元九运对应关系</div>';
    html += '<div style="font-size:12px;color:' + paper2 + ';line-height:1.8;margin-bottom:8px">一个甲子60年恰好覆盖上元/中元/下元各20年（3运），形成宏观命运背景。</div>';
    html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(240px,1fr));gap:8px">';
    for (var si = 0; si < sc.jiaziYunMap.length; si++) {
      var jy = sc.jiaziYunMap[si];
      html += '<div style="padding:10px;background:rgba(201,168,76,0.06);border-radius:6px;border-left:3px solid #e74c3c">';
      html += '<div style="font-size:13px;color:' + gold + ';font-weight:bold">' + jy.segment + ' · ' + jy.yunName + '</div>';
      html += '<div style="font-size:11px;color:' + paper2 + '">' + jy.yearRange + ' | ' + jy.ageRange + '</div>';
      html += '<div style="font-size:11px;color:' + paper2 + '">五行：' + jy.yunWuxing + ' | 方位：' + jy.yunDirection + '</div>';
      if (jy.industries) html += '<div style="font-size:11px;color:#48c9b0;margin-top:2px">行业：' + jy.industries + '</div>';
      html += '</div>';
    }
    html += '</div></div>';

    // 大运交接与运星交替共振效应
    if (sc.resonanceEffects && sc.resonanceEffects.length > 0) {
      html += '<div style="padding:12px;background:rgba(142,68,173,0.04);border-radius:8px;margin-bottom:14px">';
      html += '<div style="font-size:13px;color:var(--violet);font-weight:bold;margin-bottom:8px">🌀 大运交接与运星交替共振效应</div>';
      html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:8px">';
      for (var ri = 0; ri < sc.resonanceEffects.length; ri++) {
        var re = sc.resonanceEffects[ri];
        html += '<div style="padding:8px 10px;background:rgba(142,68,173,0.06);border-radius:6px">';
        html += '<div style="font-size:13px;color:' + gold + ';font-weight:bold">' + re.dayun + ' (' + re.ageRange + ')</div>';
        html += '<div style="font-size:11px;color:' + paper2 + '">' + re.yearRange + '</div>';
        html += '<div style="font-size:12px;color:' + paper + ';line-height:1.6;margin-top:4px">' + re.relation + '</div>';
        html += '</div>';
      }
      html += '</div></div>';
    }

    // 九紫离火运对各日主的影响
    html += '<div style="padding:12px;background:rgba(231,76,60,0.06);border-radius:8px;margin-bottom:14px">';
    html += '<div style="font-size:13px;color:#e74c3c;font-weight:bold;margin-bottom:8px">🔥 九紫离火运(2024-2043)对' + sc.dayMasterFull + '日主的影响</div>';
    html += '<div style="font-size:13px;color:' + paper + ';line-height:1.8;padding:8px 12px;background:rgba(231,76,60,0.04);border-radius:6px">' + sc.dayMasterImpact + '</div>';
    html += '</div>';

    // 催旺方位与化解建议
    html += '<div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:14px">';
    html += '<div style="padding:12px;background:rgba(231,76,60,0.06);border-radius:8px;border-left:3px solid #e74c3c">';
    html += '<div style="font-size:12px;color:#e74c3c;font-weight:bold;margin-bottom:6px">🔼 催旺方位</div>';
    html += '<div style="font-size:12px;color:' + paper + ';line-height:1.6">' + sc.cuiwangDirection + '</div>';
    html += '</div>';
    html += '<div style="padding:12px;background:rgba(41,128,185,0.06);border-radius:8px;border-left:3px solid #2980b9">';
    html += '<div style="font-size:12px;color:#2980b9;font-weight:bold;margin-bottom:6px">🔽 化解方位</div>';
    html += '<div style="font-size:12px;color:' + paper + ';line-height:1.6">' + sc.huajieDirection + '</div>';
    html += '</div>';
    html += '</div>';

    // 运星交替时间线
    if (sc.yunTimeline && sc.yunTimeline.length > 0) {
      html += '<div style="padding:12px;background:rgba(201,168,76,0.04);border-radius:8px">';
      html += '<div style="font-size:13px;color:' + gold + ';font-weight:bold;margin-bottom:10px">⏰ 缘主一生运星交替时间线</div>';
      html += '<div style="position:relative;padding-left:20px">';
      html += '<div style="position:absolute;left:6px;top:0;bottom:0;width:2px;background:linear-gradient(to bottom,#e74c3c,var(--gold),#48c9b0)"></div>';
      for (var yt = 0; yt < sc.yunTimeline.length; yt++) {
        var yl = sc.yunTimeline[yt];
        var dotC = yl.isTransition ? '#e74c3c' : '#48c9b0';
        html += '<div style="position:relative;margin-bottom:10px;padding:8px 10px;background:rgba(201,168,76,0.03);border-radius:6px">';
        html += '<div style="position:absolute;left:-17px;top:12px;width:10px;height:10px;border-radius:50%;background:' + dotC + ';border:2px solid var(--bg-card)"></div>';
        html += '<div style="display:flex;justify-content:space-between;align-items:center">';
        html += '<span style="font-size:13px;font-weight:600;color:' + dotC + '">' + yl.yunName + '</span>';
        html += '<span style="font-size:12px;color:' + gold + '">' + yl.age + '岁 · ' + yl.year + '年</span>';
        html += '</div>';
        if (yl.isTransition && yl.prevYunName) {
          html += '<div style="font-size:11px;color:#e74c3c;margin-top:2px">🔄 运星交替：' + yl.prevYunName + ' → ' + yl.yunName + '</div>';
        }
        html += '<div style="font-size:11px;color:' + paper2 + '">五行：' + yl.yunWuxing + ' | 方位：' + yl.yunDirection + '</div>';
        html += '</div>';
      }
      html += '</div></div>';
    }

    html += '</div>';
  }

  // 免责声明
  html += '<div style="margin-top:20px;padding:16px;background:rgba(231,76,60,0.05);border:1px solid rgba(231,76,60,0.15);border-radius:8px;text-align:center"><div style="font-size:12px;color:#e74c3c;font-weight:600;margin-bottom:4px">⚠ 免责声明</div><div style="font-size:11px;color:' + paper2 + ';line-height:1.8">本平台内容仅供国学文化学习与娱乐参考，不构成任何专业建议。占卜结果不作为决策依据。</div></div>';

  // 页脚
  html += '<div style="text-align:center;padding:16px;font-size:12px;color:' + paper2 + ';opacity:0.5;letter-spacing:2px">易道智鉴 · 六十甲子周期推算 · ' + new Date().toLocaleDateString('zh-CN') + '</div>';

  return html;
}

/**
 * HTML按钮入口函数
 */
function runJiaziCycle() {
 try {
  var name = (document.getElementById('jiaziName') || {}).value || '';
  var sex = (document.getElementById('jiaziSex') || {}).value || 'male';
  var dateStr = (document.getElementById('jiaziDate') || {}).value || '';
  var hourVal = (document.getElementById('jiaziHour') || {}).value || '';

  if (!dateStr) {
    showToast('请输入出生日期');
    return;
  }

  var parts = dateStr.split('-');
  if (parts.length !== 3) {
    showToast('日期格式错误');
    return;
  }
  var year = parseInt(parts[0]);
  var month = parseInt(parts[1]);
  var day = parseInt(parts[2]);
  var hour = hourVal ? parseInt(hourVal) : 12;

  playSound('cast');

  var resultEl = document.getElementById('jiaziResult');
  if (resultEl) {
    resultEl.innerHTML = '<div class="loading-spinner"><div class="spinner"></div><p>正在推演六十甲子周期...</p></div>';
    resultEl.style.display = 'block';
  }

  setTimeout(function() {
    try {
      var data = computeJiaziCycle(name, sex, year, month, day, hour);
      var html = renderJiaziCycleReport(data);
      if (resultEl) {
        resultEl.innerHTML = html;
        resultEl.style.display = 'block';
        playSound('success');
        resultEl.scrollIntoView({ behavior: 'smooth', block: 'start' });
        // 导出/复制按钮
        resultEl.innerHTML += '<div style="margin-top:16px;text-align:center"><button onclick="exportReportGeneric(\'jiaziResult\',\'六十甲子周期报告\')" style="font-size:12px;color:var(--gold);background:none;border:1px solid rgba(201,168,76,.2);border-radius:20px;padding:6px 20px;cursor:pointer;letter-spacing:2px;margin:0 4px">📄 导出报告</button><button onclick="copyReportGeneric(\'jiaziResult\')" style="font-size:12px;color:var(--gold);background:none;border:1px solid rgba(201,168,76,.2);border-radius:20px;padding:6px 20px;cursor:pointer;letter-spacing:2px;margin:0 4px">📋 复制结果</button></div>';
      }
    } catch(e) {
      if (resultEl) {
        resultEl.innerHTML = '<div style="color:#e74c3c;padding:12px">六十甲子推算出错：' + e.message + '</div>';
      }
    }
  }, 200);
 } catch(e) {
  console.error('[六十甲子周期错误]', e.message, e.stack);
  showToast('六十甲子周期分析出错: ' + e.message);
  var _r = document.getElementById('jiaziResult');
  if(_r) _r.innerHTML = '<div style="padding:20px;margin:16px 0;background:rgba(231,76,60,.08);border:1px solid rgba(231,76,60,.2);border-radius:8px"><h5 style="color:#e74c3c">❌ 六十甲子分析出错</h5><p style="font-size:13px;opacity:.8;margin-top:8px">'+e.message+'</p></div>';
 }
}

// 暴露到window
try { window.computeJiaziCycle = computeJiaziCycle; } catch(e){}
try { window.renderJiaziCycleReport = renderJiaziCycleReport; } catch(e){}
try { window.runJiaziCycle = runJiaziCycle; } catch(e){}

// ================================================================
// ===== 多人参与择日 (MULTI_ZERI) =====
// 搬家、装修、结婚、生子、开业、签约等多人合参择日系统
// ================================================================

/**
 * 关系权重配置
 */
var MULTI_ZERI_WEIGHTS = {
  '本人': 1.0,
  '配偶': 0.8,
  '父母': 0.6,
  '子女': 0.6,
  '其他': 0.4
};

/**
 * 多人事项配置（复用PRECISION_EVENT_CONFIG，补充映射）
 */
var MULTI_ZERI_PURPOSE_MAP = {
  '搬家': '搬家',
  '装修': '动土',
  '结婚': '婚嫁',
  '生子': '问名',
  '开业': '开业',
  '签约': '签合同'
};

/**
 * 评估某日对某个人的吉凶评分
 * @param {Object} dayGZ - 当日干支 {gan, zhi}
 * @param {Object} personYS - 日主用神信息
 * @param {string} purpose - 事项类型
 * @param {Object} eventConfig - 事项配置
 * @param {Object} dayData - 当日基础数据 {jcName, jsList, xsList, zs, zsHuangdao, shaInfo}
 * @returns {Object} {score, details, hasChong, hasSha}
 */
function _evalDayForMulti(dayGZ, personYS, purpose, eventConfig, dayData) {
  var score = 0;
  var details = [];
  var hasChong = false;
  var hasSha = false;

  // -- 1. 日干支与日主关系（30分） --
  var dayGanEle = ELE[TIAN_GAN[dayGZ.gan]];
  var s1Score = 20; // 基础分
  var rel = _wuxingRelation(personYS.dayEle, dayGanEle);
  if (rel === '被生') {
    s1Score += 8;
    details.push('日干' + dayGanEle + '生日主' + personYS.dayEle + '（吉）');
  } else if (rel === '生') {
    s1Score -= 3;
    details.push('日主生日干（泄气）');
  } else if (rel === '被克') {
    s1Score -= 5;
    details.push('日干克日主（忌）');
  } else if (rel === '相同') {
    if (personYS.isStrong) {
      s1Score -= 2;
      details.push('比劫帮身，身强不喜');
    } else {
      s1Score += 3;
      details.push('比劫帮身，身弱喜比劫');
    }
  }
  // 日干喜用神
  if (dayGanEle === personYS.yongshenEle || dayGanEle === personYS.xiEle) {
    s1Score += 5;
    details.push('日干为喜用' + dayGanEle);
  } else if (dayGanEle === personYS.jiEle) {
    s1Score -= 4;
    details.push('日干为忌神' + dayGanEle);
  }
  // 日支关系
  var zhiRelations = _checkZhiRelation(personYS.branchIdx, dayGZ.zhi);
  var zhiScore = 0;
  for (var z = 0; z < zhiRelations.length; z++) {
    zhiScore += zhiRelations[z].score;
    details.push('日支' + zhiRelations[z].type + '：' + zhiRelations[z].desc);
    if (zhiRelations[z].type === '六冲') hasChong = true;
  }
  s1Score += Math.max(-6, Math.min(6, zhiScore));
  // 日支冲日主日支（一票否决）
  var chongPairs = [[0,6],[1,7],[2,8],[3,9],[4,10],[5,11]];
  for (var ci = 0; ci < chongPairs.length; ci++) {
    if ((chongPairs[ci][0] === personYS.branchIdx && chongPairs[ci][1] === dayGZ.zhi) ||
        (chongPairs[ci][1] === personYS.branchIdx && chongPairs[ci][0] === dayGZ.zhi)) {
      hasChong = true;
      s1Score -= 15;
      details.push('日支冲日主日支，大忌');
    }
  }
  s1Score = Math.max(5, Math.min(30, s1Score));
  score += s1Score;

  // -- 2. 冲煞检测（一票否决） --
  var shaInfo = dayData.shaInfo;
  var personShengXiao = SHENG_XIAO[personYS.branchIdx];
  if (shaInfo && shaInfo.chong === personShengXiao) {
    hasSha = true;
    details.push('当日冲' + shaInfo.chong + '（生肖' + personShengXiao + '），犯冲煞');
  }

  // -- 3. 建除事项匹配（20分） --
  var s2Score = 10;
  var jcName = dayData.jcName;
  if (eventConfig.jianchu && eventConfig.jianchu.indexOf(jcName) !== -1) {
    s2Score = 20;
    details.push('建除「' + jcName + '」日，宜' + purpose);
  } else {
    var yiList = JIAN_CHU_YI[jcName] || ['祭祀'];
    var matchYi = false;
    for (var yi = 0; yi < yiList.length; yi++) {
      if (yiList[yi].indexOf(purpose) >= 0 || purpose.indexOf(yiList[yi]) >= 0) {
        matchYi = true; break;
      }
    }
    if (matchYi) {
      s2Score = 15;
      details.push('建除「' + jcName + '」日，宜表中含' + purpose);
    } else {
      s2Score = 8;
      details.push('建除「' + jcName + '」日，非' + purpose + '首选');
    }
  }
  score += s2Score;

  // -- 4. 吉凶神（20分） --
  var s3Score = 10;
  var jsList = dayData.jsList;
  var xsList = dayData.xsList;
  var goodFound = [];
  var badFound = [];
  if (eventConfig.good) {
    for (var g = 0; g < eventConfig.good.length; g++) {
      if (jsList.indexOf(eventConfig.good[g]) !== -1) goodFound.push(eventConfig.good[g]);
    }
  }
  if (eventConfig.bad) {
    for (var b = 0; b < eventConfig.bad.length; b++) {
      if (xsList.indexOf(eventConfig.bad[b]) !== -1) badFound.push(eventConfig.bad[b]);
    }
  }
  s3Score += goodFound.length * 3;
  s3Score -= badFound.length * 5;
  if (dayData.zsHuangdao) s3Score += 2;
  s3Score = Math.max(3, Math.min(20, s3Score));
  details.push((goodFound.length > 0 ? '吉神' + goodFound.join('、') : '无匹配吉神') +
    (badFound.length > 0 ? '；凶神' + badFound.join('、') + '不利' : '；无重凶神') +
    '。' + (dayData.zsHuangdao ? '黄道' : '黑道') + '日');
  score += s3Score;

  return {
    score: Math.max(10, Math.min(100, score + 30)), // 基础30+最高70=100
    details: details,
    hasChong: hasChong,
    hasSha: hasSha,
    s1: s1Score,
    s2: s2Score,
    s3: s3Score
  };
}

/**
 * 多人合参推算当日吉时（选所有人都可用的吉时）
 * @param {Object} dayGZ - 当日干支
 * @param {Array} personYSList - 所有人用神信息数组
 * @returns {Array} 吉时列表
 */
function _suggestMultiGoodHour(dayGZ, personYSList) {
  var dayGan = dayGZ.gan;
  var dayGanIdx = (typeof dayGan === 'number') ? dayGan : 0;
  var hourNames = ['子时(23-1)','丑时(1-3)','寅时(3-5)','卯时(5-7)','辰时(7-9)','巳时(9-11)','午时(11-13)','未时(13-15)','申时(15-17)','酉时(17-19)','戌时(19-21)','亥时(21-23)'];
  var zhiEle = ['水','土','木','木','土','火','火','土','金','金','土','水'];
  var chongMap = {0:6, 1:7, 2:8, 3:9, 4:10, 5:11, 6:0, 7:1, 8:2, 9:3, 10:4, 11:5};
  var dayZhiIdx = (typeof dayGZ.zhi === 'number') ? dayGZ.zhi : 0;
  var chongHour = chongMap[dayZhiIdx];
  // 黄黑道
  var d = dayGanIdx % 5;
  var hourHuangdao = [
    [0,1,4,5,10],
    [2,3,4,5,10],
    [0,1,6,7,10],
    [0,1,2,3,8],
    [0,1,4,5,6]
  ];
  var goodHours = hourHuangdao[d] || [4,5,6];

  var hourScores = [];
  for (var h = 0; h < 12; h++) {
    if (h === chongHour) continue; // 日支冲时支跳过
    var totalScore = 0;
    var allGood = true;
    for (var pi = 0; pi < personYSList.length; pi++) {
      var ys = personYSList[pi];
      var pScore = 50;
      if (goodHours.indexOf(h) >= 0) pScore += 15;
      else pScore -= 10;
      var hEle = zhiEle[h];
      if (hEle === ys.yongshenEle) pScore += 20;
      else if (hEle === ys.jiEle) { pScore -= 15; allGood = false; }
      // 时支冲任何人日支则跳过
      var personChongHour = chongMap[ys.branchIdx];
      if (h === personChongHour) { allGood = false; pScore -= 20; }
      totalScore += pScore;
    }
    var avgScore = totalScore / personYSList.length;
    hourScores.push({
      hour: h,
      name: hourNames[h],
      score: Math.round(avgScore),
      allGood: allGood
    });
  }
  hourScores.sort(function(a, b) { return b.score - a.score; });
  var topHours = hourScores.slice(0, 3);
  // 优先 allGood 的
  var best = topHours.filter(function(h) { return h.allGood; });
  if (best.length > 0) return best;
  return topHours;
}

/**
 * 多人参与择日主函数
 * @param {Array} persons - 参与人信息数组 [{name, sex, birthDate, birthHour, birthplace, residence, relation}]
 * @param {string} purpose - 事项类型：搬家/装修/结婚/生子/开业/签约
 * @param {Object} dateRange - {startDate, endDate}
 * @returns {Object} result
 */
function computeZeRiMulti(persons, purpose, dateRange) {
  var result = {
    persons: persons,
    purpose: purpose,
    candidates: [],
    topCandidates: [],
    avoidDates: [],
    report: null
  };

  if (!persons || persons.length === 0) {
    result.error = '至少需要一名参与人';
    result.report = '<div style="color:#e74c3c;padding:12px">至少需要一名参与人</div>';
    return result;
  }
  if (persons.length > 6) {
    result.error = '最多支持6名参与人';
    result.report = '<div style="color:#e74c3c;padding:12px">最多支持6名参与人</div>';
    return result;
  }

  // === 解析每个人的八字 ===
  var personDataList = [];
  for (var i = 0; i < persons.length; i++) {
    var p = persons[i];
    if (!p.birthDate) {
      result.error = '第' + (i + 1) + '位参与人缺少出生日期';
      result.report = '<div style="color:#e74c3c;padding:12px">' + result.error + '</div>';
      return result;
    }
    var bDate = new Date(p.birthDate + 'T12:00:00');
    var bYear = bDate.getFullYear();
    var bMonth = bDate.getMonth() + 1;
    var bDay = bDate.getDate();
    var bHour = parseInt(p.birthHour) || 0;
    var bSex = p.sex || 'male';
    var bazi = {};
    try {
      bazi = getBaziCalcData(bYear, bMonth, bDay, bHour, bSex);
    } catch(e) {
      bazi = { dayStem: '甲', dayBranch: '子', dayStemIdx: 0, dayBranchIdx: 0, dayWuxing: '木', xiEle: '水', isStrong: false, mingType: { strengthLevel: '偏弱', yongshenEle: '水', yongshen: '' } };
    }
    var ys = _extractYongShen(bazi);
    var weight = MULTI_ZERI_WEIGHTS[p.relation] || 0.5;
    personDataList.push({
      person: p,
      bazi: bazi,
      ys: ys,
      weight: weight
    });
  }

  // === 事项配置 ===
  var mappedPurpose = MULTI_ZERI_PURPOSE_MAP[purpose] || purpose;
  var eventConfig = PRECISION_EVENT_CONFIG[mappedPurpose] || {
    jianchu: ['开','成','满'],
    good: ['天恩','月恩'],
    bad: ['月破'],
    jieqi: [],
    jieqiBonus: '',
    desc: purpose
  };

  // === 搜索范围 ===
  var searchStart, searchEnd;
  if (dateRange && dateRange.startDate) {
    searchStart = new Date(dateRange.startDate + 'T12:00:00');
  } else {
    searchStart = new Date();
  }
  searchStart.setHours(12, 0, 0, 0);
  if (dateRange && dateRange.endDate) {
    searchEnd = new Date(dateRange.endDate + 'T12:00:00');
  } else {
    searchEnd = new Date(searchStart);
    searchEnd.setDate(searchEnd.getDate() + 60);
  }
  searchEnd.setHours(12, 0, 0, 0);
  var totalDays = Math.round((searchEnd - searchStart) / 86400000);
  if (totalDays < 1) totalDays = 60;
  if (totalDays > 365) totalDays = 365;

  var personYSList = personDataList.map(function(pd) { return pd.ys; });

  // === 逐日评分 ===
  for (var dayIdx = 0; dayIdx < totalDays; dayIdx++) {
    var d = new Date(searchStart);
    d.setDate(d.getDate() + dayIdx);
    d.setHours(12, 0, 0, 0);

    var Y = d.getFullYear(), M = d.getMonth() + 1, D = d.getDate();
    var yearGZ = getYearGanZhi(Y, M, D);
    var monthGZ = getMonthGanZhi(Y, M, D);
    var dayGZ = getDayGanZhi(Y, M, D);

    // 基础数据
    var jcName = getJianChu(monthGZ.zhi, dayGZ.zhi);
    var jsList = calcJishen(yearGZ, monthGZ, dayGZ);
    var xsList = calcXiongshen(yearGZ, monthGZ, dayGZ);
    var zs = getZhishen(dayGZ.gan, dayGZ.zhi);
    var zsHuangdao = ZHISHEN_TYPE[zs];
    var shaInfo = CHONGSHA_DETAIL[DI_ZHI[dayGZ.zhi]] || { chong: '?', sha: '?' };

    var dayData = {
      jcName: jcName,
      jsList: jsList,
      xsList: xsList,
      zs: zs,
      zsHuangdao: zsHuangdao,
      shaInfo: shaInfo
    };

    // 逐人评分
    var personScores = [];
    var personDetails = [];
    var anyChong = false;
    var anySha = false;
    var chongPersonNames = [];
    var shaPersonNames = [];

    for (var pi = 0; pi < personDataList.length; pi++) {
      var pd = personDataList[pi];
      var evalRes = _evalDayForMulti(dayGZ, pd.ys, mappedPurpose, eventConfig, dayData);
      personScores.push({
        name: pd.person.name || ('参与人' + (pi + 1)),
        relation: pd.person.relation || '其他',
        score: evalRes.score,
        details: evalRes.details,
        hasChong: evalRes.hasChong,
        hasSha: evalRes.hasSha,
        weight: pd.weight
      });
      personDetails.push(evalRes.details);
      if (evalRes.hasChong) {
        anyChong = true;
        chongPersonNames.push(pd.person.name || ('参与人' + (pi + 1)));
      }
      if (evalRes.hasSha) {
        anySha = true;
        shaPersonNames.push(pd.person.name || ('参与人' + (pi + 1)));
      }
    }

    // 综合评分 = 加权平均
    var totalWeight = 0;
    var weightedSum = 0;
    for (var wi = 0; wi < personScores.length; wi++) {
      weightedSum += personScores[wi].score * personScores[wi].weight;
      totalWeight += personScores[wi].weight;
    }
    var combinedScore = totalWeight > 0 ? Math.round(weightedSum / totalWeight) : 50;

    // 冲煞一票否决：标记为慎选
    var vetoed = anyChong || anySha;
    if (vetoed) {
      combinedScore = Math.min(combinedScore, 35);
    }

    // 协同加分：所有人都不冲
    if (!vetoed) {
      var allGoodCount = personScores.filter(function(ps) { return ps.score >= 70; }).length;
      if (allGoodCount === personScores.length) combinedScore += 5;
      // 吉神多
      var goodCount = 0;
      for (var gi = 0; gi < jsList.length; gi++) {
        if (eventConfig.good && eventConfig.good.indexOf(jsList[gi]) !== -1) goodCount++;
      }
      if (goodCount >= 3) combinedScore += 3;
      // 建除匹配
      if (eventConfig.jianchu && eventConfig.jianchu.indexOf(jcName) !== -1) combinedScore += 2;
      // 凶神减分
      var badCount = 0;
      for (var bi = 0; bi < xsList.length; bi++) {
        if (eventConfig.bad && eventConfig.bad.indexOf(xsList[bi]) !== -1) badCount++;
      }
      if (badCount > 0) combinedScore -= 4;
    }

    // 三元九运维度
    var _curYY3 = getCurrentYuanYun(d.getFullYear());
    var _yunWx3 = _curYY3.wuxing;
    var _dgEle3 = ELE[TIAN_GAN[dayGZ.gan]] || '木';
    if (_dgEle3 === '火' || _dgEle3 === '土') combinedScore += 5;
    else if (_dgEle3 === '水') combinedScore -= 3;

    combinedScore = Math.max(10, Math.min(100, combinedScore));

    // 等级
    var level = '';
    if (combinedScore >= 85) level = '大吉';
    else if (combinedScore >= 70) level = '吉';
    else if (combinedScore >= 55) level = '平';
    else if (combinedScore >= 40) level = '小凶';
    else level = '凶';

    // 吉时合参
    var goodHours = vetoed ? [] : _suggestMultiGoodHour(dayGZ, personYSList);

    var candidate = {
      date: new Date(d),
      ganzhi: TIAN_GAN[dayGZ.gan] + DI_ZHI[dayGZ.zhi],
      combinedScore: combinedScore,
      level: level,
      personScores: personScores,
      jianchu: jcName,
      zhishen: zs,
      isHuangdao: zsHuangdao,
      jishenList: jsList,
      xiongshenList: xsList,
      chongsha: shaInfo,
      vetoed: vetoed,
      chongPersonNames: chongPersonNames,
      shaPersonNames: shaPersonNames,
      goodHours: goodHours,
      yearGZ: yearGZ,
      monthGZ: monthGZ,
      dayGZ: dayGZ
    };

    result.candidates.push(candidate);
  }

  // 排序
  result.candidates.sort(function(a, b) {
    return b.combinedScore - a.combinedScore;
  });

  // Top5
  result.topCandidates = result.candidates.filter(function(c) { return !c.vetoed; }).slice(0, 5);
  if (result.topCandidates.length === 0) {
    // 如果全被否决，取分最高的5个
    result.topCandidates = result.candidates.slice(0, 5);
  }

  // 避开日期：被否决的或低分日
  result.avoidDates = result.candidates.filter(function(c) {
    return c.vetoed || c.combinedScore < 45;
  }).slice(0, 5);

  // 生成报告
  result.report = _generateMultiZeRiReport(result, personDataList);

  return result;
}

/**
 * 生成多人合参择日报告
 */
function _generateMultiZeRiReport(result, personDataList) {
  var top = result.topCandidates;
  var avoid = result.avoidDates;
  var purpose = result.purpose;
  var weekDays = ['周日','周一','周二','周三','周四','周五','周六'];

  var html = '<div class="precision-report">';
  html += '<div class="pr-header">👨‍👩‍👧‍👦 多人合参择日报告</div>';

  // 参与人信息
  html += '<div class="pr-meta">';
  for (var i = 0; i < personDataList.length; i++) {
    var pd = personDataList[i];
    var bzStr = pd.bazi.pillars ?
      pd.bazi.pillars[0].stem + pd.bazi.pillars[0].branch + ' ' +
      pd.bazi.pillars[1].stem + pd.bazi.pillars[1].branch + ' ' +
      pd.bazi.pillars[2].stem + pd.bazi.pillars[2].branch + ' ' +
      pd.bazi.pillars[3].stem + pd.bazi.pillars[3].branch : pd.ys.dayStem + pd.ys.dayEle + '日主';
    html += '<span>' + (pd.person.name || ('参与人' + (i + 1))) +
      '（' + (pd.person.relation || '其他') + '）：' + bzStr +
      '，日主' + pd.ys.dayEle + (pd.ys.isStrong ? '偏强' : '偏弱') +
      '，喜' + pd.ys.xiEle + '</span>';
  }
  html += '<span>事项：' + purpose + '</span>';
  html += '</div>';

  // Top5吉日
  if (top.length === 0) {
    html += '<div style="padding:16px;text-align:center;color:#e74c3c">在搜索范围内未找到所有参与人都合适的吉日，建议扩大日期范围或调整参与人。</div>';
  } else {
    html += '<div class="pr-section"><div class="pr-section-title">✨ Top' + top.length + ' 推荐吉日</div></div>';
    for (var ti = 0; ti < top.length; ti++) {
      var c = top[ti];
      var dateStr = c.date.getFullYear() + '-' +
        String(c.date.getMonth() + 1).padStart(2, '0') + '-' +
        String(c.date.getDate()).padStart(2, '0');
      var wDay = weekDays[c.date.getDay()];

      html += '<div class="pr-card">';
      html += '<div class="pr-card-header">';
      html += '<span class="pr-date">' + dateStr + ' ' + wDay + '</span>';
      html += '<span class="pr-gz">' + c.ganzhi + '日</span>';
      html += '<span class="pr-level pr-level-' + c.level + '">' + c.level + '</span>';
      if (c.vetoed) {
        html += '<span style="color:#e74c3c;font-size:12px">⚠️ 慎选</span>';
      }
      html += '</div>';

      html += '<div class="pr-score-bar"><div class="pr-score-fill" style="width:' + c.combinedScore + '%;background:' +
        (c.combinedScore >= 85 ? 'linear-gradient(90deg,#27ae60,#2ecc71)' :
         c.combinedScore >= 70 ? 'linear-gradient(90deg,#f39c12,#f1c40f)' :
         c.combinedScore >= 55 ? 'linear-gradient(90deg,#3498db,#5dade2)' :
         'linear-gradient(90deg,#e74c3c,#c0392b)') + '"></div>' +
        '<span class="pr-score-text">综合评分 ' + c.combinedScore + '/100</span></div>';

      // 每人单独评分
      html += '<div style="margin-top:10px">';
      for (var psi = 0; psi < c.personScores.length; psi++) {
        var ps = c.personScores[psi];
        var psColor = ps.score >= 75 ? '#27ae60' : ps.score >= 55 ? '#f39c12' : '#e74c3c';
        var flag = '';
        if (ps.hasChong) flag += ' ⚠️冲';
        if (ps.hasSha) flag += ' ⚠️煞';
        html += '<div style="display:flex;align-items:center;gap:8px;margin:4px 0;font-size:12px">' +
          '<span style="min-width:80px">' + ps.name + '(' + ps.relation + ')</span>' +
          '<div style="flex:1;height:6px;background:rgba(0,0,0,.06);border-radius:3px;overflow:hidden">' +
          '<div style="width:' + ps.score + '%;height:100%;background:' + psColor + '"></div></div>' +
          '<span style="min-width:30px;text-align:right;color:' + psColor + '">' + ps.score + '</span>' +
          '<span style="font-size:11px;color:#e74c3c">' + flag + '</span></div>';
      }
      html += '</div>';

      // 建除/值神/吉神
      html += '<div class="pr-card-info">';
      html += '建除「' + c.jianchu + '」· 值神' + c.zhishen + (c.isHuangdao ? '(黄道)' : '(黑道)') + '<br>';
      html += '吉神：' + (c.jishenList.length > 0 ? c.jishenList.join('、') : '无') + '<br>';
      html += '凶神：' + (c.xiongshenList.length > 0 ? c.xiongshenList.join('、') : '无') + '<br>';
      html += '冲煞：冲' + c.chongsha.chong + ' 煞' + c.chongsha.sha;
      html += '</div>';

      // 吉时
      if (c.goodHours && c.goodHours.length > 0) {
        html += '<div style="margin-top:8px;font-size:12px;color:var(--gold)">🕐 吉时（多人合参）：';
        for (var ghi = 0; ghi < c.goodHours.length; ghi++) {
          html += c.goodHours[ghi].name + '(' + c.goodHours[ghi].score + '分)';
          if (ghi < c.goodHours.length - 1) html += ' · ';
        }
        html += '</div>';
      } else if (c.vetoed) {
        html += '<div style="margin-top:8px;font-size:12px;color:#e74c3c">⚠️ 此日有人犯冲煞，不推荐吉时</div>';
      }

      html += '</div>';
    }
  }

  // 避开日期
  if (avoid.length > 0) {
    html += '<div class="pr-section"><div class="pr-section-title">⚠️ 建议避开的日期</div></div>';
    for (var ai = 0; ai < avoid.length; ai++) {
      var ac = avoid[ai];
      var aDateStr = ac.date.getFullYear() + '-' +
        String(ac.date.getMonth() + 1).padStart(2, '0') + '-' +
        String(ac.date.getDate()).padStart(2, '0');
      var aReasons = [];
      if (ac.chongPersonNames && ac.chongPersonNames.length > 0) {
        aReasons.push(ac.chongPersonNames.join('、') + '冲日支');
      }
      if (ac.shaPersonNames && ac.shaPersonNames.length > 0) {
        aReasons.push(ac.shaPersonNames.join('、') + '犯冲煞(生肖)');
      }
      if (ac.combinedScore < 45 && !ac.vetoed) {
        aReasons.push('综合评分过低(' + ac.combinedScore + '分)');
      }
      html += '<div style="padding:8px 12px;margin:4px 0;background:rgba(231,76,60,.05);border-left:3px solid #e74c3c;border-radius:4px;font-size:12px">' +
        aDateStr + ' ' + ac.ganzhi + '日 — ' + (aReasons.length > 0 ? aReasons.join('；') : '评分' + ac.combinedScore) + '</div>';
    }
  }

  // 综合建议
  html += '<div class="pr-section"><div class="pr-section-title">📋 综合建议</div></div>';
  html += '<div style="padding:12px;background:rgba(108,92,231,.05);border-radius:8px;font-size:13px;line-height:1.8">';
  if (top.length > 0 && !top[0].vetoed) {
    var best = top[0];
    var bestDateStr = best.date.getFullYear() + '-' +
      String(best.date.getMonth() + 1).padStart(2, '0') + '-' +
      String(best.date.getDate()).padStart(2, '0');
    html += '综合' + personDataList.length + '位参与人八字合参，推荐首选 <b style="color:var(--gold)">' + bestDateStr + ' ' + best.ganzhi + '日</b>，综合评分' + best.combinedScore + '分。';
    if (best.goodHours && best.goodHours.length > 0) {
      html += '建议在 <b>' + best.goodHours[0].name + '</b> 行事为佳。';
    }
    html += '<br>该日建除「' + best.jianchu + '」' + (best.isHuangdao ? '，黄道吉日' : '') + '，吉神' + (best.jishenList.length > 0 ? best.jishenList.join('、') : '无') + '。';
    // 检查是否有人评分偏低
    var lowScorers = best.personScores.filter(function(ps) { return ps.score < 55; });
    if (lowScorers.length > 0) {
      html += '<br><span style="color:#f39c12">注意：' + lowScorers.map(function(ls) { return ls.name; }).join('、') + '的单独评分偏低，但综合来看仍可选用。</span>';
    }
  } else {
    html += '在所选日期范围内，所有日期均有参与人犯冲煞。建议扩大搜索范围，或咨询专业命理师进行更精细的择日。';
  }
  html += '</div>';

  // 免责声明
  html += '<div style="margin-top:16px;padding:16px;background:rgba(108,92,231,.03);border:1px solid rgba(108,92,231,.1);border-radius:8px;text-align:center">';
  html += '<p style="font-size:12px;color:var(--gold);opacity:.5;line-height:1.8">⚠️ 免责声明：以上推荐基于传统命理学多人八字合参理论，仅供参考。实际择日还需结合家庭安排、天气等因素综合决定。</p>';
  html += '</div>';

  // ═══ 三元九运择日维度 ═══
  try {
    html += _generateSanyuanJiuyunBlock('zeri', {
      currentYear: new Date().getFullYear()
    });
  } catch(e) { console.warn('[三元九运多人择日分析块失败]', e.message); }

  html += '</div>';

  return html;
}

// ================================================================
// ===== 多人择日 UI 交互 =====
// ================================================================

/**
 * 参与人计数器
 */
var _multiZeriPersonCount = 0;

/**
 * 添加参与人卡片
 */
function addZeRiPerson() {
  if (_multiZeriPersonCount >= 6) {
    showToast('最多支持6名参与人');
    return;
  }
  var idx = _multiZeriPersonCount;
  _multiZeriPersonCount++;

  var listEl = document.getElementById('multiZeriPersonList');
  if (!listEl) return;

  var card = document.createElement('div');
  card.id = 'multiZeriPerson_' + idx;
  card.style.cssText = 'margin-bottom:12px;padding:12px;border:1px solid rgba(108,92,231,.15);border-radius:8px;background:rgba(108,92,231,.02)';

  var relationColor = idx === 0 ? '#6c5ce7' : '#a29bfe';
  var relationLabel = idx === 0 ? '本人（首选）' : '参与人' + (idx + 1);

  var html = '';
  html += '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px">';
  html += '<span style="font-size:13px;color:' + relationColor + ';font-weight:bold">👤 ' + relationLabel + '</span>';
  if (idx > 0) {
    html += '<button onclick="removeZeRiPerson(' + idx + ')" style="background:none;border:none;color:#e74c3c;cursor:pointer;font-size:16px;padding:4px 8px" title="删除">✕</button>';
  }
  html += '</div>';
  html += '<div class="input-row" style="justify-content:flex-start;flex-wrap:wrap;gap:8px">';
  html += '<input type="text" id="multiZeriName_' + idx + '" class="input-field" placeholder="姓名(选填)" style="max-width:100px">';
  html += '<select id="multiZeriSex_' + idx + '" class="input-field" style="max-width:80px"><option value="male">男</option><option value="female">女</option></select>';
  html += '<input type="date" id="multiZeriBirth_' + idx + '" class="input-field" style="max-width:150px;text-align:center" placeholder="出生日期">';
  html += '<select id="multiZeriHour_' + idx + '" class="input-field" style="max-width:110px">';
  html += '<option value="0">子时(23-1)</option><option value="1">丑时(1-3)</option><option value="2">寅时(3-5)</option><option value="3">卯时(5-7)</option><option value="4">辰时(7-9)</option><option value="5">巳时(9-11)</option><option value="6">午时(11-13)</option><option value="7">未时(13-15)</option><option value="8">申时(15-17)</option><option value="9">酉时(17-19)</option><option value="10">戌时(19-21)</option><option value="11">亥时(21-23)</option>';
  html += '</select>';
  html += '</div>';
  html += '<div class="input-row" style="justify-content:flex-start;flex-wrap:wrap;gap:8px;margin-top:8px">';
  html += '<input type="text" id="multiZeriBirthplace_' + idx + '" class="input-field" placeholder="出生地(选填)" style="max-width:140px">';
  html += '<input type="text" id="multiZeriResidence_' + idx + '" class="input-field" placeholder="居住地(选填)" style="max-width:140px">';
  html += '<select id="multiZeriRelation_' + idx + '" class="input-field" style="max-width:120px">';
  var relOpts = ['本人','配偶','父母','子女','其他'];
  for (var ri = 0; ri < relOpts.length; ri++) {
    html += '<option value="' + relOpts[ri] + '"' + (idx === 0 && relOpts[ri] === '本人' ? ' selected' : '') + '>' + relOpts[ri] + '</option>';
  }
  html += '</select>';
  html += '</div>';

  card.innerHTML = html;
  listEl.appendChild(card);

  // 更新添加按钮状态
  var addBtn = document.getElementById('multiZeriAddBtn');
  if (addBtn) {
    if (_multiZeriPersonCount >= 6) {
      addBtn.style.opacity = '0.5';
      addBtn.disabled = true;
    }
  }
}

/**
 * 删除参与人卡片
 */
function removeZeRiPerson(idx) {
  var card = document.getElementById('multiZeriPerson_' + idx);
  if (card) {
    card.remove();
  }
  // 不减少计数器，避免ID冲突
  // 但检查是否可以重新启用添加按钮
  var remaining = 0;
  for (var i = 0; i < _multiZeriPersonCount; i++) {
    if (document.getElementById('multiZeriPerson_' + i)) remaining++;
  }
  if (remaining < 6) {
    var addBtn = document.getElementById('multiZeriAddBtn');
    if (addBtn) {
      addBtn.style.opacity = '1';
      addBtn.disabled = false;
    }
  }
  if (remaining === 0) {
    // 如果删完了，重置并自动添加一个
    _multiZeriPersonCount = 0;
    addZeRiPerson();
  }
}

/**
 * 执行多人择日
 */
function runZeRiMulti() {
  // 收集参与人信息
  var persons = [];
  for (var i = 0; i < _multiZeriPersonCount; i++) {
    var card = document.getElementById('multiZeriPerson_' + i);
    if (!card) continue;
    var name = (document.getElementById('multiZeriName_' + i) || {}).value || '';
    var sex = (document.getElementById('multiZeriSex_' + i) || {}).value || 'male';
    var birthDate = (document.getElementById('multiZeriBirth_' + i) || {}).value || '';
    var birthHour = (document.getElementById('multiZeriHour_' + i) || {}).value || '0';
    var birthplace = (document.getElementById('multiZeriBirthplace_' + i) || {}).value || '';
    var residence = (document.getElementById('multiZeriResidence_' + i) || {}).value || '';
    var relation = (document.getElementById('multiZeriRelation_' + i) || {}).value || '其他';
    if (!birthDate) {
      showToast('请填写第' + (i + 1) + '位参与人的出生日期');
      return;
    }
    persons.push({
      name: name,
      sex: sex,
      birthDate: birthDate,
      birthHour: birthHour,
      birthplace: birthplace,
      residence: residence,
      relation: relation
    });
  }

  if (persons.length === 0) {
    showToast('请至少添加一名参与人');
    return;
  }

  var purpose = (document.getElementById('multiZeriPurpose') || {}).value || '搬家';
  var startDate = (document.getElementById('multiZeriStartDate') || {}).value || '';
  var endDate = (document.getElementById('multiZeriEndDate') || {}).value || '';
  var dateRange = { startDate: startDate, endDate: endDate };

  playSound('cast');

  var resultEl = document.getElementById('multiZeriResult');
  if (resultEl) {
    resultEl.innerHTML = '<div class="loading-spinner"><div class="spinner"></div><p>正在推演多人合参择日...</p></div>';
    resultEl.style.display = 'block';
  }

  setTimeout(function() {
    try {
      var result = computeZeRiMulti(persons, purpose, dateRange);
      if (resultEl) {
        resultEl.innerHTML = result.report || '<div style="color:#e74c3c;padding:12px">推演失败</div>';
        resultEl.style.display = 'block';
        playSound('success');
        resultEl.scrollIntoView({ behavior: 'smooth', block: 'start' });
      }
    } catch(e) {
      if (resultEl) {
        resultEl.innerHTML = '<div style="color:#e74c3c;padding:12px">多人择日出错：' + e.message + '</div>';
      }
    }
  }, 200);
}

// 暴露多人择日函数到window
try { window.computeZeRiMulti = computeZeRiMulti; } catch(e){}
try { window.addZeRiPerson = addZeRiPerson; } catch(e){}
try { window.removeZeRiPerson = removeZeRiPerson; } catch(e){}
try { window.runZeRiMulti = runZeRiMulti; } catch(e){}

// 页面加载后自动初始化第一个参与人
try {
  if (typeof document !== 'undefined') {
    document.addEventListener('DOMContentLoaded', function() {
      // 检查是否在择日页面
      if (document.getElementById('multiZeriPersonList')) {
        addZeRiPerson();
      }
    });
  }
} catch(e){}

// ═══ 排盘模式切换 ═══
function toggleDivinationMode(tool, mode) {
  var resultEl = null;
  var prefix = '';
  switch(tool) {
    case 'qimen': resultEl = document.getElementById('qmResult'); prefix = 'qm'; break;
    case 'ziwei': resultEl = document.getElementById('zwResult'); prefix = 'zw'; break;
    case 'bazi': resultEl = document.getElementById('baziResult'); prefix = 'bazi'; break;
    case 'yijing': resultEl = document.getElementById('yjResult'); prefix = 'yj'; break;
    case 'liuren': resultEl = document.getElementById('lrResult'); prefix = 'lr'; break;
  }
  if (!resultEl) return;
  if (mode === 'pro') {
    resultEl.classList.add('pro-mode');
    resultEl.classList.remove('simple-mode');
  } else {
    resultEl.classList.add('simple-mode');
    resultEl.classList.remove('pro-mode');
  }
}
window.toggleDivinationMode = toggleDivinationMode;

