// 在紫微排盘中注入副星分析
function injectZiweiFuStarsAnalysis(mingGongTianGanIdx, mingGongBranchIdx, yearStemIdx, monthBranchIdx) {
  var html = '';
  try {
    var fuStars = computeZwFuStars(mingGongTianGanIdx, mingGongBranchIdx, yearStemIdx, monthBranchIdx);
    html += '<div class="interp-card violet-accent" style="margin-top:16px">';
    html += '<h5>⭐ 紫微副星分析</h5>';
    html += '<div style="display:grid;grid-template-columns:repeat(2,1fr);gap:8px;margin-top:8px">';
    var gongNames = ['子','丑','寅','卯','辰','巳','午','未','申','酉','戌','亥'];
    for (var starName in fuStars) {
      var s = fuStars[starName];
      var color = s.nature === '吉' ? '#2ecc71' : '#e74c3c';
      html += '<div style="padding:8px;background:rgba(155,89,182,.04);border-radius:6px">';
      html += '<div style="font-size:12px;color:' + color + ';font-weight:bold">' + starName + ' <span style="opacity:.5;font-weight:normal">(' + s.method + ')</span></div>';
      html += '<div style="font-size:11px;opacity:.6;margin-top:2px">落' + gongNames[s.gongIdx] + '宫</div>';
      html += '<div style="font-size:11px;opacity:.7;margin-top:4px">' + s.desc + '</div>';
      html += '</div>';
    }
    html += '</div></div>';
  } catch(e) {
    console.warn('[紫微副星分析失败]', e.message);
  }
  return html;
}

// 在风水中注入三合水法分析
function injectFengshuiSanheAnalysis(direction) {
  var html = '';
  try {
    var sanhe = computeSanheFengshui(direction);
    html += '<div class="interp-card gold-accent" style="margin-top:16px">';
    html += '<h5>🌊 三合风水（长生水法）</h5>';
    html += '<p style="font-size:13px;color:var(--gold)">宅向「' + direction + '」→ ' + sanhe.juName + '</p>';
    if (sanhe.positions && sanhe.positions.length > 0) {
      html += '<p style="font-size:12px;opacity:.7;white-space:pre-wrap">' + sanhe.analysis + '</p>';
      html += '<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:4px;margin-top:8px">';
      for (var i = 0; i < sanhe.positions.length; i++) {
        var pos = sanhe.positions[i];
        var stageColor = '';
        if (pos.stage === '帝旺' || pos.stage === '长生' || pos.stage === '临官' || pos.stage === '冠带') stageColor = '#2ecc71';
        else if (pos.stage === '死' || pos.stage === '绝' || pos.stage === '病') stageColor = '#e74c3c';
        else stageColor = '#f39c12';
        html += '<div style="padding:4px;background:rgba(201,168,76,.04);border-radius:4px;text-align:center;font-size:10px">';
        html += '<div style="color:' + stageColor + ';font-weight:bold">' + pos.branch + '</div>';
        html += '<div style="opacity:.6">' + pos.stage + '</div>';
        html += '</div>';
      }
      html += '</div>';
    }
    html += '</div>';
  } catch(e) {
    console.warn('[三合风水分析失败]', e.message);
  }
  return html;
}

