// ═══════ 补全：大运空亡 ═══════
function getDayunKongWang(dayunArr, pillars, dayStem) {
  var xunKong = getXunKong(pillars[2].stem, pillars[2].branch);
  if (!xunKong) return [];
  var kongBranch = xunKong.split('');
  var result = [];
  for (var i = 0; i < dayunArr.length; i++) {
    if (dayunArr[i] && kongBranch.indexOf(dayunArr[i].zhi) >= 0) {
      result.push({ index: i, name: dayunArr[i].gan + dayunArr[i].zhi, age: dayunArr[i].ageStart + '-' + dayunArr[i].ageEnd + '岁' });
    }
  }
  return result;
}
