// ═══════ 补全：三奇得使 ═══════
function checkSanqiDeshi(palaces) {
  var jiMen = ['休','开','生'];
  var result = [];
  for (var i = 1; i <= 9; i++) {
    if (!palaces[i] || !palaces[i].door) continue;
    var doorKey = palaces[i].door.name || '';
    if (jiMen.indexOf(doorKey) < 0) continue;
    // 检查是否有乙丙丁三奇
    var gan = palaces[i].heavenGan || '';
    if (gan === '乙') result.push('乙奇临'+doorKey+'门·'+'得使');
    if (gan === '丙') result.push('丙奇临'+doorKey+'门·'+'得使');
    if (gan === '丁') result.push('丁奇临'+doorKey+'门·'+'得使');
  }
  return result;
}
try { window.checkSanqiDeshi = checkSanqiDeshi; } catch(e){}

