  var shenZhuMap = {0:'火星',1:'天相',2:'天梁',3:'天同',4:'文昌',5:'天机',6:'火星',7:'天相',8:'天梁',9:'天同',10:'文昌',11:'天机'};
  var mingZhu = mingZhuMap[mingGongGanIdx] || '贪狼';
  var shenZhu = shenZhuMap[shenGongBranchIdx] || '火星';
