// ═══ DOMContentLoaded 安全保护 ═══
// 确保日期输入框有默认值（即使前面的DOMContentLoaded报错）
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', function() {
    try {
      var today = new Date();
      var y = today.getFullYear();
      var m = String(today.getMonth()+1).padStart(2,'0');
      var d = String(today.getDate()).padStart(2,'0');
      var ds = y + '-' + m + '-' + d;
      var inputs = document.querySelectorAll('input[type="date"]');
      inputs.forEach(function(el) { if (el && !el.value) { el.value = ds; el.max = ds; } });
    } catch(e) { console.warn('[date init fallback]', e.message); }
  });
} else {
  // DOM已就绪，立即设置
  try {
    var today = new Date();
    var y = today.getFullYear();
    var m = String(today.getMonth()+1).padStart(2,'0');
    var d = String(today.getDate()).padStart(2,'0');
    var ds = y + '-' + m + '-' + d;
    var inputs = document.querySelectorAll('input[type="date"]');
    inputs.forEach(function(el) { if (el && !el.value) { el.value = ds; el.max = ds; } });
  } catch(e) { console.warn('[date init fallback]', e.message); }
}

// ═══ 排盘按钮安全检查 ═══
// 在window load后检查所有onclick函数是否可用
window.addEventListener('load', function() {
  try {
    var btns = document.querySelectorAll('[onclick]');
    var missing = {};
    btns.forEach(function(btn) {
      var onclick = btn.getAttribute('onclick') || '';
      var fnMatch = onclick.match(/^(\w+)\s*\(/);
      if (fnMatch) {
        var fnName = fnMatch[1];
        if (typeof window[fnName] !== 'function' && fnName !== 'document' && fnName !== 'if' && fnName !== 'event' && fnName !== 'this') {
          if (!missing[fnName]) {
            missing[fnName] = 0;
          }
          missing[fnName]++;
        }
      }
    });
    var missingList = Object.keys(missing);
    if (missingList.length > 0) {
      console.warn('[排盘安全检查] 以下函数未定义:', missingList.join(', '));
    }
  } catch(e) { console.warn('[btn check]', e.message); }
});

